import type { ReactElement, ReactNode } from "react";
import React, { useMemo, useState } from "react";
import { Button } from "../Button";
import { useOptionalFormContext } from "./FormWrapper";
import { FormFieldSet } from "./FormFieldSet";

const escapeRegExp = (value: unknown) =>
  String(value).replace(/[.*+?^${}()|[\]\\]/g, "\\$&");

export type LoopFieldsHelpers = {
  count: number;
  minItems: number;
  maxItems: number;
  canAdd: boolean;
  canRemove: boolean;
  addItem: () => void;
  removeItem: (index?: number) => void;
  removeLastItem: () => void;
};

export type LoopFieldsProps = {
  children: ReactNode | ((index: number, helpers: LoopFieldsHelpers) => ReactNode);
  minItems?: number;
  maxItems?: number;
  addTitle?: string;
  removeTitle?: string;
  size?: React.ComponentProps<typeof Button>["size"];
  className?: string;
  group?: string;
  nameStrategy?: "suffix" | "bracket";
  controls?: "top" | "none";
};

const sanitize = (str: unknown) =>
  String(str || "")
    .toLowerCase()
    .replace(/\s+/g, "_")
    .replace(/[^a-z0-9_]/g, "");

const getChildBaseName = (child: ReactElement) => {
  const p: any = child?.props || {};
  return sanitize(p.name ?? p.id ?? p.label ?? p.placeholder ?? "field");
};

const collectBases = (node: ReactNode): string[] => {
  if (!React.isValidElement(node)) return [];
  if (node.type === FormFieldSet) return [getChildBaseName(node as ReactElement)];
  const childNodes = (node as any).props?.children;
  if (!childNodes) return [];
  const arr: string[] = [];
  React.Children.forEach(childNodes, (c) => {
    const bases = collectBases(c);
    if (bases.length) arr.push(...bases);
  });
  return arr;
};

const cloneWithIndex = (
  node: ReactNode,
  index: number,
  group?: string,
  nameStrategy?: string,
): ReactNode => {
  if (!React.isValidElement(node)) return node;
  if (node.type === FormFieldSet) {
    const base = getChildBaseName(node as ReactElement);
    const suffix =
      nameStrategy === "bracket" && group
        ? `${group}[${index}].${base}`
        : `${base}_${index}`;
    return React.cloneElement(node, {
      key: suffix,
      name: suffix,
      id: suffix,
    } as any);
  }
  const childNodes = (node as any).props?.children;
  if (!childNodes) return node;
  const mapped = React.Children.map(childNodes, (c) =>
    cloneWithIndex(c, index, group, nameStrategy),
  ) as ReactNode;
  return React.cloneElement(node, { children: mapped } as any);
};

export const LoopFields = (props: LoopFieldsProps) => {
  const {
    children,
    minItems = 0,
    maxItems = 5,
    addTitle = "Add",
    removeTitle = "Remove",
    size = "sm",
    className = "",
    group,
    nameStrategy = "suffix",
    controls = "top",
  } = props;

  const formContext = useOptionalFormContext();
  const initialCount = useMemo(() => (minItems < 1 ? 1 : minItems), [minItems]);
  const [count, setCount] = useState(initialCount);

  const addItem = () => setCount((c) => (c >= maxItems ? c : c + 1));

  const removeItem = (removeIndex?: number) => {
    const resolvedIndex =
      typeof removeIndex === "number" ? removeIndex : Math.max(0, count - 1);

    if (resolvedIndex < 0 || resolvedIndex >= count) return;
    const nextCount = count - 1;
    if (nextCount < minItems) return;

    if (formContext) {
      const prevForm = formContext.formData || {};

      if (nameStrategy === "bracket" && group) {
        const re = new RegExp(`^${escapeRegExp(group)}\\[(\\d+)\\]\\.(.+)$`);
        const nextForm: any = {};
        Object.entries(prevForm).forEach(([key, value]) => {
          const m = key.match(re);
          if (!m) {
            nextForm[key] = value;
            return;
          }
          const idxStr = m[1];
          const field = m[2];
          if (!idxStr || !field) {
            nextForm[key] = value;
            return;
          }
          const idx = parseInt(idxStr, 10);
          if (idx < resolvedIndex) {
            nextForm[key] = value;
            return;
          }
          if (idx === resolvedIndex) return;
          nextForm[`${group}[${idx - 1}].${field}`] = value;
        });
        formContext.setFormData(nextForm);
      } else {
        const templateHelpers: LoopFieldsHelpers = {
          count,
          minItems,
          maxItems,
          canAdd: count < maxItems,
          canRemove: count > minItems,
          addItem: () => {},
          removeItem: () => {},
          removeLastItem: () => {},
        };
        const templateNode =
          typeof children === "function" ? children(0, templateHelpers) : children;
        const bases = Array.from(new Set(collectBases(templateNode)));

        if (!bases.length) {
          formContext.setFormData(prevForm);
        } else {
          const re = new RegExp(`^(${bases.map(escapeRegExp).join("|")})_(\\d+)$`);
          const nextForm: any = {};
          Object.entries(prevForm).forEach(([key, value]) => {
            const m = key.match(re);
            if (!m) {
              nextForm[key] = value;
              return;
            }
            const base = m[1];
            const idxStr = m[2];
            if (!base || !idxStr) {
              nextForm[key] = value;
              return;
            }
            const idx = parseInt(idxStr, 10);
            if (idx < resolvedIndex) {
              nextForm[key] = value;
              return;
            }
            if (idx === resolvedIndex) return;
            nextForm[`${base}_${idx - 1}`] = value;
          });
          formContext.setFormData(nextForm);
        }
      }
    }

    setCount(nextCount);
  };

  const removeLastItem = () => removeItem(count - 1);

  const helpers: LoopFieldsHelpers = {
    count,
    minItems,
    maxItems,
    canAdd: count < maxItems,
    canRemove: count > minItems,
    addItem,
    removeItem,
    removeLastItem,
  };

  const renderItem = (index: number) => {
    const node = typeof children === "function" ? children(index, helpers) : children;
    if (Array.isArray(node)) return node.map((n) => cloneWithIndex(n, index, group, nameStrategy));
    return cloneWithIndex(node, index, group, nameStrategy);
  };

  return (
    <div className={className}>
      {controls === "top" ? (
        <div style={{ display: "flex", gap: "8px", alignItems: "center" }}>
          <Button
            variant="bordered"
            size={size}
            onClick={addItem}
            isDisabled={!helpers.canAdd}
          >
            {addTitle}
          </Button>
          <Button
            variant="bordered"
            size={size}
            onClick={removeLastItem}
            isDisabled={!helpers.canRemove}
          >
            {removeTitle}
          </Button>
        </div>
      ) : null}
      <div style={{ display: "flex", flexDirection: "column", gap: "16px" }}>
        {Array.from({ length: count }).map((_, i) => (
          <div key={`loop_item_${i}`} style={{ display: "flex", flexDirection: "column", gap: "16px" }}>
            {renderItem(i)}
          </div>
        ))}
      </div>
    </div>
  );
};

export const loopGroupToArray = (formData: Record<string, unknown>, groupName: string) => {
  const result: any[] = [];
  const re = new RegExp(`^${escapeRegExp(groupName)}\\[(\\d+)\\]\\.(.+)$`);
  Object.keys(formData || {}).forEach((key) => {
    const m = key.match(re);
    if (!m) return;
    const idxStr = m[1];
    const field = m[2];
    if (!idxStr || !field) return;
    const idx = parseInt(idxStr, 10);
    if (!result[idx]) result[idx] = {};
    result[idx][field] = (formData as any)[key];
  });
  return result.filter((x) => x && Object.keys(x).length > 0);
};
