import type { CSSProperties, ReactNode } from "react";
import type { TooltipProps } from "../Tooltip";
import { Tooltip } from "../Tooltip";
import "./PageTitle.module.css";

export type PageTitleAs = "h1" | "h2" | "h3" | "h4" | "h5" | "h6";

export type PageTitleColor =
  | "default"
  | "primary"
  | "info"
  | "success"
  | "warning"
  | "danger"
  | "secondary"
  | "black"
  | "white"
  | (string & {});

export type PageTitleSlot = "base" | "title" | "icon";

export type PageTitleClassNames = Partial<Record<PageTitleSlot, string>>;

export type PageTitleTooltipLegacy = {
  message: ReactNode;
  disabled?: boolean;
  side?: "top" | "right" | "bottom" | "left";
  align?: "start" | "center" | "end";
  openDelay?: number;
  closeDelay?: number;
  portal?: boolean;
  className?: string;
};

export type PageTitleTooltip =
  | boolean
  | Omit<TooltipProps, "children" | "content">
  | {
      props?: Omit<TooltipProps, "children" | "content">;
      content?: ReactNode;
    }
  | PageTitleTooltipLegacy;

export type PageTitleProps = {
  title?: ReactNode;
  as?: PageTitleAs;
  tag?: PageTitleAs;
  color?: PageTitleColor;
  colorDepth?: number;
  icon?: ReactNode;
  iconPosition?: "start" | "end" | "before" | "after";
  tooltip?: PageTitleTooltip;
  className?: string;
  titleClassName?: string;
  classNames?: PageTitleClassNames;
  style?: CSSProperties;
};

function mergeClassName(a: unknown, b: unknown) {
  const sa = typeof a === "string" ? a : "";
  const sb = typeof b === "string" ? b : "";
  return [sa, sb].filter(Boolean).join(" ");
}

const ALLOWED_DEPTHS = [
  50, 100, 200, 300, 400, 500, 600, 700, 800, 900, 950,
] as const;

function snapDepth(input: number) {
  const clamped = Math.min(950, Math.max(50, input));
  const first: number = ALLOWED_DEPTHS[0] ?? 500;
  let best: number = first;
  let bestDiff = Math.abs(best - clamped);
  for (const d of ALLOWED_DEPTHS) {
    const diff = Math.abs(d - clamped);
    if (diff < bestDiff) {
      best = d;
      bestDiff = diff;
    }
  }
  return best;
}

function normalizeIconPosition(
  input: PageTitleProps["iconPosition"],
): "start" | "end" {
  if (input === "end" || input === "after") return "end";
  return "start";
}

function getColorVar(color: string, depth: number) {
  const fallback = `var(--oks-color-default-${depth}, var(--oks-color-primary-${depth}, #3b82f6))`;
  if (color === "default") return fallback;
  return `var(--oks-color-${color}-${depth}, ${fallback})`;
}

function getTextColor(color: PageTitleColor, depth: number): string {
  if (color === "black" || color === "white") return color;
  return getColorVar(color, depth);
}

function isLegacyTooltip(
  tooltip: PageTitleTooltip | undefined,
): tooltip is PageTitleTooltipLegacy {
  return (
    typeof tooltip === "object" &&
    tooltip !== null &&
    "message" in tooltip &&
    (tooltip as any).message !== undefined
  );
}

export function PageTitle(props: PageTitleProps) {
  const {
    title = "Title",
    as,
    tag,
    color,
    colorDepth = 500,
    icon,
    iconPosition = "start",
    tooltip,
    className,
    titleClassName,
    classNames,
    style,
  } = props;

  const depth = snapDepth(colorDepth);
  const position = normalizeIconPosition(iconPosition);
  const Tag: PageTitleAs = as ?? tag ?? "h4";

  const resolvedColor = (color ?? "black") as PageTitleColor;

  type ResolvedTooltip = {
    content: ReactNode;
    props: Omit<TooltipProps, "children" | "content">;
  };

  const tooltipInfo: ResolvedTooltip | null = (() => {
    if (tooltip === undefined || tooltip === null) return null;
    if (tooltip === false) return null;

    if (isLegacyTooltip(tooltip)) {
      if (tooltip.message === undefined || tooltip.message === null)
        return null;
      const placement: TooltipProps["placement"] =
        tooltip.side === undefined
          ? undefined
          : tooltip.align === "start"
            ? `${tooltip.side}-start`
            : tooltip.align === "end"
              ? `${tooltip.side}-end`
              : tooltip.side;

      const props: Omit<TooltipProps, "children" | "content"> = {
        ...(tooltip.disabled !== undefined
          ? { isDisabled: tooltip.disabled }
          : {}),
        ...(placement !== undefined ? { placement } : {}),
        ...(tooltip.openDelay !== undefined
          ? { delay: tooltip.openDelay }
          : {}),
        ...(tooltip.closeDelay !== undefined
          ? { closeDelay: tooltip.closeDelay }
          : {}),
        ...(tooltip.className !== undefined
          ? { className: tooltip.className }
          : {}),
      };

      return { content: tooltip.message, props };
    }

    const derivedFromTitle =
      typeof title === "string" && title.trim().length > 0 ? title : null;

    if (tooltip === true) {
      return derivedFromTitle ? { content: derivedFromTitle, props: {} } : null;
    }

    if (typeof tooltip === "object") {
      if ("props" in tooltip || "content" in tooltip) {
        const t = tooltip as {
          props?: Omit<TooltipProps, "children" | "content">;
          content?: ReactNode;
        };
        const content = t.content !== undefined ? t.content : derivedFromTitle;
        return content ? { content, props: t.props ?? {} } : null;
      }

      const t = tooltip as Omit<TooltipProps, "children" | "content">;
      return derivedFromTitle ? { content: derivedFromTitle, props: t } : null;
    }

    return null;
  })();

  const hasTooltip = tooltipInfo !== null;

  const renderIcon = () => {
    if (icon === undefined || icon === null) return null;
    return (
      <span className={mergeClassName("oksPageTitleIcon", classNames?.icon)}>
        {icon}
      </span>
    );
  };

  const element = (
    <div
      className={mergeClassName(
        mergeClassName("oksPageTitle", classNames?.base),
        className,
      )}
      style={{ color: getTextColor(resolvedColor, depth), ...style }}
      data-color={resolvedColor}
      data-icon-position={position}
      data-has-tooltip={hasTooltip ? "true" : "false"}
    >
      {position === "start" ? renderIcon() : null}
      <Tag
        className={mergeClassName(
          mergeClassName("oksPageTitleTitle", classNames?.title),
          titleClassName,
        )}
      >
        {title}
      </Tag>
      {position === "end" ? renderIcon() : null}
    </div>
  );

  if (tooltipInfo) {
    const tooltipProps: Omit<TooltipProps, "children"> = {
      ...(tooltipInfo.props as any),
      content: tooltipInfo.content,
    };
    return <Tooltip {...tooltipProps}>{element}</Tooltip>;
  }

  return element;
}

export default PageTitle;
