import type {
  ButtonHTMLAttributes,
  CSSProperties,
  HTMLAttributes,
  ReactNode,
} from "react";
import { forwardRef, useCallback, useMemo, useState } from "react";
import { CloseIcon, StatusIcon } from "../../internal/icons/StatusIcons";
import "./Alert.module.css";

export type AlertColor =
  | "default"
  | "primary"
  | "secondary"
  | "info"
  | "success"
  | "warning"
  | "danger";

export type AlertVariant = "solid" | "bordered" | "flat" | "faded";

export type AlertRadius = "none" | "sm" | "md" | "lg" | "full";

export type AlertSlot =
  | "base"
  | "title"
  | "description"
  | "mainWrapper"
  | "closeButton"
  | "iconWrapper"
  | "alertIcon";

export type AlertClassNames = Partial<Record<AlertSlot, string>>;

export type AlertProps = Omit<
  HTMLAttributes<HTMLDivElement>,
  "color" | "title"
> & {
  title?: ReactNode;
  description?: ReactNode;
  color?: AlertColor;
  variant?: AlertVariant;
  radius?: AlertRadius;
  icon?: ReactNode;
  startContent?: ReactNode;
  endContent?: ReactNode;
  isVisible?: boolean;
  isClosable?: boolean;
  hideIcon?: boolean;
  hideIconWrapper?: boolean;
  closeButtonProps?: Omit<ButtonHTMLAttributes<HTMLButtonElement>, "type">;
  onClose?: () => void;
  onVisibleChange?: (isVisible: boolean) => void;
  classNames?: AlertClassNames;
  style?: CSSProperties;
};

function mergeClassName(a: unknown, b: unknown) {
  const sa = typeof a === "string" ? a : "";
  const sb = typeof b === "string" ? b : "";
  return [sa, sb].filter(Boolean).join(" ");
}

function mapColorToStatusIconType(color: AlertColor) {
  if (color === "success") return "success";
  if (color === "warning") return "warning";
  if (color === "danger") return "error";
  if (color === "default") return "default";
  if (color === "info") return "info";
  return "info";
}

function getColorVar(color: string, depth: number) {
  const fallback = `var(--oks-color-default-${depth}, var(--oks-color-primary-${depth}, #3b82f6))`;
  if (color === "default") return fallback;
  return `var(--oks-color-${color}-${depth}, ${fallback})`;
}

export const Alert = forwardRef<HTMLDivElement, AlertProps>((props, ref) => {
  const {
    title,
    description,
    color = "default",
    variant = "flat",
    radius = "md",
    icon,
    startContent,
    endContent,
    isVisible,
    isClosable = false,
    hideIcon = false,
    hideIconWrapper = false,
    closeButtonProps,
    onClose,
    onVisibleChange,
    classNames,
    className,
    style,
    ...rest
  } = props;

  const [uncontrolledVisible, setUncontrolledVisible] = useState(true);
  const isControlled = typeof isVisible === "boolean";
  const resolvedVisible = isControlled ? isVisible : uncontrolledVisible;

  const hasTitle = title !== undefined && title !== null;
  const hasDescription = description !== undefined && description !== null;

  const toneVars: CSSProperties = useMemo(() => {
    const accent = getColorVar(color, 600);
    return {
      ["--oks-alert-accent" as any]: accent,
      ["--oks-alert-bg-50" as any]: getColorVar(color, 50),
      ["--oks-alert-bg-100" as any]: getColorVar(color, 100),
      ["--oks-alert-fg-900" as any]: getColorVar(color, 900),
    } as CSSProperties;
  }, [color]);

  const defaultIcon = useMemo(
    () => <StatusIcon type={mapColorToStatusIconType(color)} size={18} />,
    [color],
  );

  const handleClose = useCallback(() => {
    onVisibleChange?.(false);
    if (!isControlled) setUncontrolledVisible(false);
    onClose?.();
  }, [isControlled, onClose, onVisibleChange]);

  if (!resolvedVisible) return null;

  const resolvedIcon = icon ?? defaultIcon;
  const shouldRenderIcon = !hideIcon && resolvedIcon !== null;

  const iconElement = shouldRenderIcon ? (
    <span className={mergeClassName("oksAlertIcon", classNames?.alertIcon)}>
      {resolvedIcon}
    </span>
  ) : null;

  const iconWrapper = shouldRenderIcon ? (
    hideIconWrapper ? (
      iconElement
    ) : (
      <span
        className={mergeClassName(
          "oksAlertIconWrapper",
          classNames?.iconWrapper,
        )}
      >
        {iconElement}
      </span>
    )
  ) : null;

  const closeButtonClassName = mergeClassName(
    mergeClassName("oksAlertCloseButton", classNames?.closeButton),
    closeButtonProps?.className,
  );

  const closeButton =
    isClosable === true ? (
      <button
        type="button"
        aria-label="Close"
        {...closeButtonProps}
        className={closeButtonClassName}
        onClick={(e) => {
          closeButtonProps?.onClick?.(e);
          if (!e.defaultPrevented) handleClose();
        }}
      >
        <CloseIcon size={16} />
      </button>
    ) : null;

  return (
    <div
      {...rest}
      ref={ref}
      role="alert"
      data-visible="true"
      data-closeable={isClosable ? "true" : "false"}
      data-has-title={hasTitle ? "true" : "false"}
      data-has-description={hasDescription ? "true" : "false"}
      data-color={color}
      data-variant={variant}
      data-radius={radius}
      className={mergeClassName(
        mergeClassName("oksAlert", classNames?.base),
        className,
      )}
      style={{ ...toneVars, ...style }}
    >
      {iconWrapper}
      {startContent}
      <div
        className={mergeClassName(
          "oksAlertMainWrapper",
          classNames?.mainWrapper,
        )}
      >
        {hasTitle ? (
          <div className={mergeClassName("oksAlertTitle", classNames?.title)}>
            {title}
          </div>
        ) : null}
        {hasDescription ? (
          <div
            className={mergeClassName(
              "oksAlertDescription",
              classNames?.description,
            )}
          >
            {description}
          </div>
        ) : null}
      </div>
      {endContent}
      {closeButton}
    </div>
  );
});

Alert.displayName = "Alert";

export default Alert;
