import type {
  CSSProperties,
  HTMLAttributes,
  ReactNode,
} from "react";
import { Children, cloneElement, forwardRef, isValidElement } from "react";
import type { ButtonColor, ButtonRadius, ButtonSize, ButtonVariant } from "./Button";
import { Button } from "./Button";
import "./ButtonGroup.module.css";

export type ButtonGroupProps = Omit<HTMLAttributes<HTMLDivElement>, "color" | "children"> & {
  children?: ReactNode;
  variant?: ButtonVariant;
  color?: ButtonColor;
  size?: ButtonSize;
  radius?: ButtonRadius;
  fullWidth?: boolean;
  isDisabled?: boolean;
  style?: CSSProperties;
};

function mergeClassName(a: unknown, b: unknown) {
  const sa = typeof a === "string" ? a : "";
  const sb = typeof b === "string" ? b : "";
  return [sa, sb].filter(Boolean).join(" ");
}

export const ButtonGroup = forwardRef<HTMLDivElement, ButtonGroupProps>(
  (props, ref) => {
    const {
      children,
      variant = "solid",
      color = "default",
      size = "md",
      radius = "md",
      fullWidth = false,
      isDisabled = false,
      className,
      role = "group",
      style,
      ...rest
    } = props;

    const enhancedChildren = Children.map(children, (child) => {
      if (!isValidElement(child) || child.type !== Button) return child;

      const nextProps: any = {};

      if (child.props.variant === undefined) nextProps.variant = variant;
      if (child.props.color === undefined) nextProps.color = color;
      if (child.props.size === undefined) nextProps.size = size;
      if (child.props.radius === undefined) nextProps.radius = radius;
      if (child.props.fullWidth === undefined) nextProps.fullWidth = fullWidth;
      if (child.props.isDisabled === undefined) nextProps.isDisabled = isDisabled;

      return cloneElement(child, nextProps);
    });

    return (
      <div
        {...rest}
        ref={ref}
        role={role}
        data-variant={variant}
        data-color={color}
        data-size={size}
        data-radius={radius}
        data-full-width={fullWidth ? "true" : "false"}
        data-disabled={isDisabled ? "true" : "false"}
        className={mergeClassName("oksButtonGroup", className)}
        style={style}
      >
        {enhancedChildren}
      </div>
    );
  },
);

ButtonGroup.displayName = "ButtonGroup";

