import type { CSSProperties, InputHTMLAttributes, ReactNode } from "react";
import { forwardRef, useEffect, useId, useState } from "react";
import type {
  FormElementLabelPlacement,
  FormElementSize,
  FormElementTone,
} from "../types";
import { getToneVar, mergeClassName } from "../internal";
import "./CheckboxGroupField.module.css";

export type CheckboxOption = {
  label: ReactNode;
  value: string;
  disabled?: boolean;
  key?: string;
};

export type CheckboxGroupFieldProps = Omit<
  InputHTMLAttributes<HTMLInputElement>,
  | "type"
  | "size"
  | "color"
  | "value"
  | "defaultValue"
  | "checked"
  | "defaultChecked"
  | "onChange"
> & {
  label?: ReactNode;
  labelPlacement?: FormElementLabelPlacement;
  description?: ReactNode;
  error?: ReactNode | boolean;
  size?: FormElementSize;
  tone?: FormElementTone;
  colorDepth?: number;
  options: CheckboxOption[];
  value?: string[];
  defaultValue?: string[];
  onChange?: (next: string[]) => void;
  style?: CSSProperties;
};

export const CheckboxGroupField = forwardRef<
  HTMLDivElement,
  CheckboxGroupFieldProps
>((props, ref) => {
  const {
    label,
    labelPlacement,
    description,
    error,
    size = "md",
    tone = "primary",
    colorDepth = 500,
    className,
    id,
    required,
    disabled,
    options,
    value,
    defaultValue,
    onChange,
    style,
    ...rest
  } = props;

  const reactId = useId();
  const groupId = id ?? `oks-checkbox-group-${reactId}`;

  const isInvalid = Boolean(error);

  const descriptionId = description ? `${groupId}-description` : undefined;
  const errorId =
    error && error !== true ? `${groupId}-error-message` : undefined;
  const ariaDescribedBy = [descriptionId, errorId].filter(Boolean).join(" ");

  const isControlled = value !== undefined;
  const normalizeValue = (source: unknown): string[] =>
    Array.isArray(source) ? source.map(String) : [];

  const [internalValue, setInternalValue] = useState<string[]>(() =>
    normalizeValue(defaultValue),
  );

  useEffect(() => {
    if (!isControlled) return;
    setInternalValue(normalizeValue(value));
  }, [isControlled, value]);

  const currentValue = isControlled ? normalizeValue(value) : internalValue;

  const toneVars: CSSProperties = {
    "--oks-checkbox-tone": getToneVar(tone, colorDepth),
  } as unknown as CSSProperties;

  const handleToggle = (val: string) => {
    if (disabled) return;
    const exists = currentValue.includes(val);
    const next = exists
      ? currentValue.filter((v) => v !== val)
      : [...currentValue, val];
    if (!isControlled) setInternalValue(next);
    onChange?.(next);
  };

  return (
    <div
      ref={ref}
      className={mergeClassName("oksCheckboxGroupField", className)}
      data-size={size}
      data-tone={tone}
      data-invalid={isInvalid ? "true" : "false"}
      data-disabled={disabled ? "true" : "false"}
      style={{ ...toneVars, ...style }}
    >
      {label ? (
        <div className="oksCheckboxGroupFieldLabel">
          {label}
          {required ? <span aria-hidden="true">*</span> : null}
        </div>
      ) : null}

      <div role="group" aria-describedby={ariaDescribedBy || undefined}>
        <div className="oksCheckboxGroupFieldItems">
          {options.map((opt, idx) => {
            const optionId = `${groupId}-${opt.key ?? `${idx}-${opt.value}`}`;
            const checked = currentValue.includes(opt.value);
            return (
              <label
                key={opt.key ?? `${idx}-${opt.value}`}
                className="oksCheckboxGroupFieldItem"
                data-disabled={disabled || opt.disabled ? "true" : "false"}
              >
                <input
                  {...rest}
                  id={optionId}
                  type="checkbox"
                  disabled={disabled || opt.disabled}
                  checked={checked}
                  onChange={() => handleToggle(opt.value)}
                  className="oksCheckboxGroupFieldInput"
                  aria-invalid={isInvalid ? "true" : undefined}
                />
                <span className="oksCheckboxGroupFieldItemLabel">{opt.label}</span>
              </label>
            );
          })}
        </div>
      </div>

      {description ? (
        <div id={descriptionId} className="oksCheckboxGroupFieldDescription">
          {description}
        </div>
      ) : null}

      {error && error !== true ? (
        <div id={errorId} className="oksCheckboxGroupFieldError" role="alert">
          {error}
        </div>
      ) : null}
    </div>
  );
});

CheckboxGroupField.displayName = "CheckboxGroupField";

