import type { CSSProperties, ReactNode, SelectHTMLAttributes } from "react";
import { forwardRef, useEffect, useId, useMemo, useRef, useState } from "react";
import type {
  FormElementLabelPlacement,
  FormElementSize,
  FormElementTone,
  FormElementVariant,
} from "../types";
import { getToneVar, mergeClassName } from "../internal";
import { Portal } from "../../../../primitives/Portal";
import { computeTooltipPosition } from "../../../Tooltip/tooltipPositioning";
import { Chip } from "../../../Chip";
import "./SelectField.module.css";

export type SelectOption = {
  label: ReactNode;
  value: string;
  disabled?: boolean;
  key?: string;
};

export type SelectFieldValue = string | string[];

export type SelectFieldProps = Omit<
  SelectHTMLAttributes<HTMLSelectElement>,
  "size" | "color"
> & {
  label?: ReactNode;
  labelPlacement?: FormElementLabelPlacement;
  description?: ReactNode;
  error?: ReactNode | boolean;
  size?: FormElementSize;
  variant?: FormElementVariant;
  color?: FormElementTone;
  tone?: FormElementTone;
  colorDepth?: number;
  radius?: "none" | "sm" | "md" | "lg" | "full";
  rounded?: "none" | "sm" | "md" | "lg" | "full";
  options?: SelectOption[];
  placeholderOption?: ReactNode;
  native?: boolean;
  onValueChange?: (value: SelectFieldValue) => void;
  style?: CSSProperties;
};

export const SelectField = forwardRef<HTMLSelectElement, SelectFieldProps>(
  (props, ref) => {
    const {
      label,
      labelPlacement = "top",
      description,
      error,
      size = "md",
      variant = "outline",
      color,
      tone,
      colorDepth = 500,
      radius,
      rounded,
      className,
      id,
      required,
      disabled,
      options = [],
      placeholderOption = "Select…",
      native = false,
      onValueChange,
      style,
      ...rest
    } = props;

    const resolvedColor = color ?? tone ?? "default";
    const resolvedRadius = radius ?? rounded ?? "md";

    const reactId = useId();
    const fieldId = id ?? `oks-select-${reactId}`;

    const describedBy = rest["aria-describedby"];
    const descriptionId = description ? `${fieldId}-description` : undefined;
    const errorId =
      error && error !== true ? `${fieldId}-error-message` : undefined;
    const ariaDescribedBy = [describedBy, descriptionId, errorId]
      .filter(Boolean)
      .join(" ");

    const isInvalid = Boolean(error);

    const isMultiple = Boolean(rest.multiple);
    const isNative = native;

    const canRenderPlaceholderOption =
      !isMultiple && placeholderOption !== null && placeholderOption !== undefined;

    const normalizeValue = (input: unknown): SelectFieldValue => {
      if (isMultiple) {
        if (Array.isArray(input)) return input.map((v) => String(v));
        return [];
      }
      if (input === null || input === undefined) return "";
      if (Array.isArray(input)) return String(input[0] ?? "");
      return String(input);
    };

    const [uncontrolledValue, setUncontrolledValue] = useState<SelectFieldValue>(() => {
      if (rest.value !== undefined) return normalizeValue(rest.value);
      if (rest.defaultValue !== undefined) return normalizeValue(rest.defaultValue);
      return isMultiple ? [] : "";
    });

    useEffect(() => {
      if (rest.value !== undefined) setUncontrolledValue(normalizeValue(rest.value));
    }, [rest.value, isMultiple]);

    const resolvedValue = rest.value !== undefined ? normalizeValue(rest.value) : uncontrolledValue;
    const selectedValues = isMultiple
      ? Array.isArray(resolvedValue)
        ? resolvedValue
        : []
      : [];
    const selectedValue = isMultiple ? "" : String(resolvedValue);

    const isPlaceholderShown = useMemo(() => {
      if (isMultiple) return selectedValues.length === 0;
      return selectedValue === "";
    }, [isMultiple, selectedValue, selectedValues.length]);

    const toneVars: CSSProperties = {
      "--oks-select-tone": getToneVar(resolvedColor, colorDepth),
    } as unknown as CSSProperties;

    const menuThemeVars = useMemo(() => {
      const result: Record<string, unknown> = { ...toneVars };
      if (style && typeof style === "object") {
        for (const [k, v] of Object.entries(style as Record<string, unknown>)) {
          if (k.startsWith("--")) result[k] = v;
        }
      }
      return result as unknown as CSSProperties;
    }, [style, toneVars]);

    const topLabel = labelPlacement === "top" ? label : null;
    const floatingLabel = labelPlacement === "floating" ? label : null;

    const triggerRef = useRef<HTMLButtonElement | null>(null);
    const menuRef = useRef<HTMLDivElement | null>(null);
    const typeaheadRef = useRef<{ value: string; timer: number | null }>({
      value: "",
      timer: null,
    });
    const [isOpen, setIsOpen] = useState(false);
    const [activeIndex, setActiveIndex] = useState<number>(0);
    const [menuStyle, setMenuStyle] = useState<CSSProperties | null>(null);
    const [filterQuery, setFilterQuery] = useState("");

    const valueLabelMap = useMemo(() => {
      const map = new Map<string, ReactNode>();
      for (const opt of options) map.set(String(opt.value), opt.label);
      return map;
    }, [options]);

    const filteredItems = useMemo(() => {
      const q = filterQuery.trim().toLowerCase();
      if (!q) return options.map((opt, idx) => ({ opt, idx }));
      return options
        .map((opt, idx) => ({ opt, idx }))
        .filter(({ opt }) => {
          const labelText = typeof opt.label === "string" ? opt.label : "";
          const hay = `${labelText} ${String(opt.value ?? "")}`.toLowerCase();
          return hay.includes(q);
        });
    }, [filterQuery, options]);

    const visibleIndices = useMemo(
      () => filteredItems.map((i) => i.idx),
      [filteredItems],
    );

    useEffect(() => {
      if (!isOpen) return;
      if (visibleIndices.length < 1) return;
      const isVisible = visibleIndices.includes(activeIndex);
      const isEnabled = !options[activeIndex]?.disabled;
      if (isVisible && isEnabled) return;
      const next =
        visibleIndices.find((i) => !options[i]?.disabled) ?? visibleIndices[0] ?? 0;
      setActiveIndex(next);
    }, [activeIndex, isOpen, options, visibleIndices]);

    useEffect(() => {
      const target = isMultiple ? selectedValues[0] : selectedValue;
      const idx = options.findIndex((o) => String(o.value) === String(target));
      if (idx >= 0) setActiveIndex(idx);
    }, [isMultiple, options, selectedValue, selectedValues, resolvedValue]);

    const canOpen = !disabled && !isNative && options.length > 0;

    const getNextEnabledIndex = (from: number, dir: 1 | -1) => {
      const enabled = visibleIndices.filter((i) => !options[i]?.disabled);
      if (enabled.length < 1) return from;
      const currentPos = enabled.indexOf(from);
      const basePos = currentPos >= 0 ? currentPos : 0;
      const nextPos = (basePos + dir + enabled.length) % enabled.length;
      return enabled[nextPos] ?? from;
    };

    const close = () => {
      setIsOpen(false);
      setFilterQuery("");
    };

    const open = () => {
      if (!canOpen) return;
      setIsOpen(true);
      const target = isMultiple ? selectedValues[0] : selectedValue;
      const selected = options.findIndex((o) => String(o.value) === String(target));
      const base = selected >= 0 ? selected : 0;
      const next = options[base]?.disabled ? getNextEnabledIndex(base, 1) : base;
      setActiveIndex(next);
    };

    const emitValue = (nextValue: SelectFieldValue, nativeEvent?: unknown) => {
      if (rest.value === undefined) setUncontrolledValue(nextValue);
      onValueChange?.(nextValue);
      if (isMultiple) {
        const syntheticEvent = { target: { value: nextValue } } as any;
        (rest as any).onChange?.(syntheticEvent);
        return;
      }
      if (nativeEvent) {
        (rest as any).onChange?.(nativeEvent);
        return;
      }
      const syntheticEvent = { target: { value: nextValue } } as any;
      (rest as any).onChange?.(syntheticEvent);
    };

    const runTypeahead = (char: string) => {
      if (!char) return;
      const nextChar = char.toLowerCase();
      const current = typeaheadRef.current.value + nextChar;
      typeaheadRef.current.value = current;
      if (typeaheadRef.current.timer) window.clearTimeout(typeaheadRef.current.timer);
      typeaheadRef.current.timer = window.setTimeout(() => {
        typeaheadRef.current.value = "";
        typeaheadRef.current.timer = null;
      }, 350);

      const findIndex = () => {
        const enabled = visibleIndices.filter((i) => !options[i]?.disabled);
        if (enabled.length < 1) return -1;
        const startPos = Math.max(0, enabled.indexOf(activeIndex));
        const ordered = [...enabled.slice(startPos), ...enabled.slice(0, startPos)];
        for (const idx of ordered) {
          const opt = options[idx];
          if (!opt) continue;
          const text =
            typeof opt.label === "string" ? opt.label : String(opt.value ?? "");
          if (text.toLowerCase().startsWith(current)) return idx;
        }
        return -1;
      };

      const idx = findIndex();
      if (idx >= 0) setActiveIndex(idx);
    };

    useEffect(() => {
      if (!isOpen) return;
      const onDocPointerDown = (e: MouseEvent | PointerEvent) => {
        const t = e.target as Node | null;
        if (!t) return;
        if (triggerRef.current?.contains(t)) return;
        if (menuRef.current?.contains(t)) return;
        close();
      };
      const onDocKeyDown = (e: KeyboardEvent) => {
        if (e.key === "Escape") {
          e.preventDefault();
          close();
          triggerRef.current?.focus();
        }
      };
      document.addEventListener("pointerdown", onDocPointerDown, true);
      document.addEventListener("keydown", onDocKeyDown, true);
      return () => {
        document.removeEventListener("pointerdown", onDocPointerDown, true);
        document.removeEventListener("keydown", onDocKeyDown, true);
      };
    }, [isOpen]);

    useEffect(() => {
      if (!isOpen) return;

      const update = () => {
        const triggerEl = triggerRef.current;
        const menuEl = menuRef.current;
        if (!triggerEl || !menuEl) return;
        const triggerRect = triggerEl.getBoundingClientRect();
        const tooltipRect = menuEl.getBoundingClientRect();
        const pos = computeTooltipPosition({
          triggerRect,
          tooltipRect,
          side: "bottom",
          align: "start",
          offset: 6,
          collisionPadding: 8,
          strategy: "fixed",
        });
        setMenuStyle({
          position: "fixed",
          top: pos.top,
          left: pos.left,
          minWidth: triggerRect.width,
        });
      };

      const raf = requestAnimationFrame(update);
      const onScroll = () => update();
      const onResize = () => update();
      window.addEventListener("scroll", onScroll, true);
      window.addEventListener("resize", onResize);
      return () => {
        cancelAnimationFrame(raf);
        window.removeEventListener("scroll", onScroll, true);
        window.removeEventListener("resize", onResize);
      };
    }, [isOpen]);

    const renderValueLabel = () => {
      const selected = options.find((o) => String(o.value) === String(selectedValue));
      if (!selected) return null;
      return selected.label;
    };

    const activeOptionId = `${fieldId}-opt-${activeIndex}`;
    const menuId = `${fieldId}-menu`;

    return (
      <div
        className={mergeClassName("oksSelectField", className)}
        data-size={size}
        data-variant={variant}
        data-color={resolvedColor}
        data-radius={resolvedRadius}
        data-label-placement={labelPlacement}
        data-placeholder-shown={isPlaceholderShown ? "true" : "false"}
        data-invalid={isInvalid ? "true" : "false"}
        data-disabled={disabled ? "true" : "false"}
        style={{ ...toneVars, ...style }}
      >
        {topLabel ? (
          <label className="oksSelectFieldLabel" htmlFor={fieldId}>
            {topLabel}
            {required ? <span aria-hidden="true">*</span> : null}
          </label>
        ) : null}

        <div className="oksSelectFieldControl">
          {isNative ? (
            <select
              {...rest}
              ref={ref}
              id={fieldId}
              required={required}
              disabled={disabled}
              className="oksSelectFieldInput"
              aria-invalid={isInvalid ? "true" : undefined}
              aria-describedby={ariaDescribedBy || undefined}
              aria-errormessage={errorId}
              value={isMultiple ? selectedValues : selectedValue}
              onChange={(e) => {
                if (isMultiple) {
                  const next = Array.from(e.currentTarget.selectedOptions).map(
                    (o) => String(o.value),
                  );
                  emitValue(next, e);
                  return;
                }
                emitValue(String(e.currentTarget.value), e);
              }}
            >
              {canRenderPlaceholderOption ? (
                <option value="" disabled={required}>
                  {placeholderOption}
                </option>
              ) : null}
              {options.map((opt, idx) => (
                <option
                  key={opt.key ?? `${idx}-${opt.value}`}
                  value={opt.value}
                  disabled={opt.disabled}
                >
                  {opt.label}
                </option>
              ))}
            </select>
          ) : (
            <>
              <button
                ref={triggerRef}
                id={fieldId}
                type="button"
                className="oksSelectFieldTrigger"
                disabled={disabled}
                aria-label={(rest as any)["aria-label"]}
                aria-labelledby={(rest as any)["aria-labelledby"]}
                aria-invalid={isInvalid ? "true" : undefined}
                aria-describedby={ariaDescribedBy || undefined}
                aria-errormessage={errorId}
                aria-haspopup="listbox"
                aria-expanded={isOpen ? "true" : "false"}
                aria-controls={isOpen ? menuId : undefined}
                aria-activedescendant={isOpen ? activeOptionId : undefined}
                onClick={() => (isOpen ? close() : open())}
                onBlur={(e) => {
                  (rest as any).onBlur?.(e);
                  requestAnimationFrame(() => {
                    const ae = document.activeElement as Node | null;
                    if (!ae) return;
                    if (triggerRef.current?.contains(ae)) return;
                    if (menuRef.current?.contains(ae)) return;
                    close();
                  });
                }}
                onKeyDown={(e) => {
                  if (disabled) return;
                  if (
                    e.key.length === 1 &&
                    !e.ctrlKey &&
                    !e.metaKey &&
                    !e.altKey
                  ) {
                    if (!isOpen) open();
                    runTypeahead(e.key);
                    return;
                  }
                  if (e.key === "ArrowDown") {
                    e.preventDefault();
                    if (!isOpen) {
                      open();
                      return;
                    }
                    setActiveIndex((i) => getNextEnabledIndex(i, 1));
                    return;
                  }
                  if (e.key === "ArrowUp") {
                    e.preventDefault();
                    if (!isOpen) {
                      open();
                      return;
                    }
                    setActiveIndex((i) => getNextEnabledIndex(i, -1));
                    return;
                  }
                  if (e.key === "Enter" || e.key === " ") {
                    e.preventDefault();
                    if (!isOpen) {
                      open();
                      return;
                    }
                    const opt = options[activeIndex];
                    if (opt && !opt.disabled) {
                      if (isMultiple) {
                        const v = String(opt.value);
                        const next = selectedValues.includes(v)
                          ? selectedValues.filter((x) => x !== v)
                          : [...selectedValues, v];
                        emitValue(next);
                      } else {
                        emitValue(String(opt.value));
                        close();
                      }
                    }
                    return;
                  }
                  if (e.key === "Escape") {
                    if (isOpen) {
                      e.preventDefault();
                      close();
                    }
                    return;
                  }
                }}
              >
                <span className="oksSelectFieldTriggerValue">
                  {isMultiple ? (
                    selectedValues.length < 1 ? (
                      placeholderOption
                    ) : (
                      <span className="oksSelectFieldChips">
                        {selectedValues.map((v) => (
                          <Chip
                            key={v}
                            size="sm"
                            variant="flat"
                            endContent={
                              <span
                                className="oksSelectFieldChipRemove"
                                role="button"
                                tabIndex={-1}
                                aria-label="Remove"
                                onMouseDown={(e) => {
                                  e.preventDefault();
                                  e.stopPropagation();
                                }}
                                onClick={(e) => {
                                  e.preventDefault();
                                  e.stopPropagation();
                                  emitValue(selectedValues.filter((x) => x !== v));
                                }}
                              >
                                ×
                              </span>
                            }
                            onMouseDown={(e) => {
                              e.preventDefault();
                              e.stopPropagation();
                            }}
                          >
                            {valueLabelMap.get(v) ?? v}
                          </Chip>
                        ))}
                      </span>
                    )
                  ) : isPlaceholderShown ? (
                    placeholderOption
                  ) : (
                    renderValueLabel()
                  )}
                </span>
              </button>

              {isOpen ? (
                <Portal>
                  <div
                    ref={menuRef}
                    id={menuId}
                    className="oksSelectFieldMenu"
                    role="listbox"
                    aria-multiselectable={isMultiple ? "true" : undefined}
                    style={menuStyle ? { ...menuThemeVars, ...menuStyle } : menuThemeVars}
                  >
                    <div className="oksSelectFieldFilter">
                      <input
                        className="oksSelectFieldFilterInput"
                        value={filterQuery}
                        onChange={(e) => setFilterQuery(String(e.currentTarget.value))}
                        placeholder="Filter…"
                        aria-label="Filter options"
                        onKeyDown={(e) => {
                          if (e.key === "ArrowDown") {
                            e.preventDefault();
                            setActiveIndex((i) => getNextEnabledIndex(i, 1));
                            return;
                          }
                          if (e.key === "ArrowUp") {
                            e.preventDefault();
                            setActiveIndex((i) => getNextEnabledIndex(i, -1));
                            return;
                          }
                          if (e.key === "Enter" || e.key === " ") {
                            e.preventDefault();
                            const opt = options[activeIndex];
                            if (opt && !opt.disabled) {
                              if (isMultiple) {
                                const v = String(opt.value);
                                const next = selectedValues.includes(v)
                                  ? selectedValues.filter((x) => x !== v)
                                  : [...selectedValues, v];
                                emitValue(next);
                              } else {
                                emitValue(String(opt.value));
                                close();
                                triggerRef.current?.focus();
                              }
                            }
                            return;
                          }
                          if (e.key === "Escape") {
                            e.preventDefault();
                            close();
                            triggerRef.current?.focus();
                          }
                        }}
                      />
                    </div>

                    {filteredItems.map(({ opt, idx }) => {
                      const isSelected = isMultiple
                        ? selectedValues.includes(String(opt.value))
                        : String(opt.value) === String(selectedValue);
                      const isActive = idx === activeIndex;
                      return (
                        <div
                          key={opt.key ?? `${idx}-${opt.value}`}
                          id={`${fieldId}-opt-${idx}`}
                          role="option"
                          aria-selected={isSelected ? "true" : "false"}
                          data-selected={isSelected ? "true" : "false"}
                          data-active={isActive ? "true" : "false"}
                          data-disabled={opt.disabled ? "true" : "false"}
                          className="oksSelectFieldOption"
                          onMouseEnter={() => {
                            if (opt.disabled) return;
                            setActiveIndex(idx);
                          }}
                          onMouseDown={(e) => e.preventDefault()}
                          onClick={() => {
                            if (opt.disabled) return;
                            if (isMultiple) {
                              const v = String(opt.value);
                              const next = selectedValues.includes(v)
                                ? selectedValues.filter((x) => x !== v)
                                : [...selectedValues, v];
                              emitValue(next);
                              return;
                            }
                            emitValue(String(opt.value));
                            close();
                            triggerRef.current?.focus();
                          }}
                        >
                          {opt.label}
                        </div>
                      );
                    })}
                  </div>
                </Portal>
              ) : null}
            </>
          )}

          {floatingLabel ? (
            <label className="oksSelectFieldLabel" htmlFor={fieldId}>
              {floatingLabel}
              {required ? <span aria-hidden="true">*</span> : null}
            </label>
          ) : null}
        </div>

        {description ? (
          <div id={descriptionId} className="oksSelectFieldDescription">
            {description}
          </div>
        ) : null}

        {error && error !== true ? (
          <div id={errorId} className="oksSelectFieldError" role="alert">
            {error}
          </div>
        ) : null}
      </div>
    );
  },
);

SelectField.displayName = "SelectField";
