import { forwardRef } from "react";
import type { Ref, ReactNode } from "react";
import { useTabsContext } from "./context";
import "./Tabs.module.css";

export type TabPanelProps = {
  value: string | number;
  keepMounted?: boolean;
  className?: string;
  children?: ReactNode;
};

export const TabPanel = forwardRef<HTMLDivElement, TabPanelProps>(function TabPanel(
  props,
  ref: Ref<HTMLDivElement>,
) {
  const { value, keepMounted, className, children } = props;
  const ctx = useTabsContext();
  const ids = ctx.getIds(value);
  const active = ctx.isActive(value);
  const cls = ["oksTabsPanel", className].filter(Boolean).join(" ");
  if (!active && keepMounted === undefined && ctx.renderLazy) {
    return null;
  }
  return (
    <div
      ref={ref}
      role="tabpanel"
      id={ids.panel}
      aria-labelledby={ids.tab}
      hidden={!active}
      className={cls}
    >
      {children}
    </div>
  );
});

TabPanel.displayName = "TabPanel";

