import type { FormHTMLAttributes, ReactNode } from "react";
import React, {
  createContext,
  forwardRef,
  useCallback,
  useContext,
  useEffect,
  useImperativeHandle,
  useRef,
  useState,
} from "react";
import type { FieldValidation } from "../Validation";
import { getFirstError, validateField, validateForm } from "../Validation";

export type FormValidationMode = "blur" | "change";

export type FormShowErrorsOn = "blur" | "change";

export type FormErrors = Record<string, string | null>;

export type FormTouched = Record<string, boolean>;

export type FormData = Record<string, unknown>;

export type FormSchema = Record<string, FieldValidation>;

export type FormHandle = {
  reset: (nextValues?: Record<string, unknown>) => void;
};

export type FormProps = Omit<FormHTMLAttributes<HTMLFormElement>, "onSubmit"> & {
  children?: ReactNode;
  onSubmit: (formData: FormData) => void | Promise<void>;
  onError?: (errors: FormErrors) => void;
  validationMode?: FormValidationMode;
  showErrorsOn?: FormShowErrorsOn;
  validateOnMount?: boolean;
  initialValues?: FormData;
  disableAutofill?: boolean;
};

export type FormContextValue = {
  formData: FormData;
  errors: FormErrors;
  touched: FormTouched;
  isSubmitting: boolean;
  disableAutofill: boolean;
  validationMode: FormValidationMode;
  showErrorsOn: FormShowErrorsOn;
  validationSchema: FormSchema;
  registerField: (fieldName: string, validation: FieldValidation) => void;
  unregisterField: (fieldName: string) => void;
  validateFieldValue: (
    fieldName: string,
    value: unknown,
    validation: FieldValidation,
  ) => string | null;
  handleFieldChange: (fieldName: string, value: unknown) => void;
  handleFieldBlur: (fieldName: string) => void;
  getUniqueFieldName: (baseName: string) => string;
  setFormData: React.Dispatch<React.SetStateAction<FormData>>;
  setErrors: React.Dispatch<React.SetStateAction<FormErrors>>;
  setTouched: React.Dispatch<React.SetStateAction<FormTouched>>;
};

const FormContext = createContext<FormContextValue | undefined>(undefined);

export const useFormContext = () => {
  const ctx = useContext(FormContext);
  if (!ctx) {
    throw new Error("useFormContext must be used within a Form");
  }
  return ctx;
};

export const useOptionalFormContext = () => useContext(FormContext);

export const Form = forwardRef<FormHandle, FormProps>((props, ref) => {
  const {
    children,
    onSubmit,
    onError,
    validationMode = "blur",
    showErrorsOn = "blur",
    className = "",
    validateOnMount = false,
    initialValues = {},
    disableAutofill = true,
    ...rest
  } = props;

  const { autoComplete: autoCompleteProp, ...restFormProps } = rest;
  const resolvedAutoComplete =
    autoCompleteProp ?? (disableAutofill ? "off" : undefined);

  const [formData, setFormData] = useState<FormData>(() => initialValues || {});
  const [errors, setErrors] = useState<FormErrors>({});
  const [touched, setTouched] = useState<FormTouched>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [validationSchema, setValidationSchema] = useState<FormSchema>({});
  const formDataRef = useRef<FormData>(initialValues || {});

  const changeTimersRef = useRef<
    Record<string, ReturnType<typeof setTimeout> | undefined>
  >({});
  const usedFieldNamesRef = useRef(new Set<string>());
  const fieldNameCountsRef = useRef<Record<string, number>>({});
  const initialValuesRef = useRef<FormData>(initialValues || {});

  useEffect(() => {
    initialValuesRef.current = initialValues || {};
  }, [initialValues]);

  useEffect(() => {
    formDataRef.current = formData;
  }, [formData]);

  const getUniqueFieldName = useCallback((baseName: string) => {
    const base = String(baseName || "field").trim() || "field";
    const used = usedFieldNamesRef.current;
    const counts = fieldNameCountsRef.current;

    if (!used.has(base)) {
      used.add(base);
      counts[base] = 1;
      return base;
    }

    let next = (counts[base] || 1) + 1;
    let candidate = `${base}_${next}`;
    while (used.has(candidate)) {
      next += 1;
      candidate = `${base}_${next}`;
    }
    counts[base] = next;
    used.add(candidate);
    return candidate;
  }, []);

  const registerField = useCallback(
    (fieldName: string, validation: FieldValidation) => {
      if (
        !validation ||
        !validation.rules ||
        Object.keys(validation.rules).length < 1
      )
        return;
      setValidationSchema((prev) => {
        const prevVal = prev[fieldName];
        const prevStr = prevVal ? JSON.stringify(prevVal) : "";
        const nextStr = JSON.stringify(validation);
        if (prevStr === nextStr) return prev;
        return { ...prev, [fieldName]: validation };
      });
    },
    [],
  );

  const unregisterField = useCallback((fieldName: string) => {
    setValidationSchema((prev) => {
      const next = { ...prev };
      delete next[fieldName];
      return next;
    });

    usedFieldNamesRef.current.delete(fieldName);

    setErrors((prev) => {
      const next = { ...prev };
      delete next[fieldName];
      return next;
    });

    setTouched((prev) => {
      const next = { ...prev };
      delete next[fieldName];
      return next;
    });
  }, []);

  const validateFieldValue = useCallback(
    (fieldName: string, value: unknown, validation: FieldValidation) => {
      if (!validation || !validation.rules) return null;
      const fieldErrors = validateField(
        value,
        validation.rules,
        validation.message ?? {},
        { formData: formDataRef.current, fieldName },
      );
      const first = getFirstError(fieldErrors);
      setErrors((prev) => ({ ...prev, [fieldName]: first }));
      return first;
    },
    [],
  );

  const handleFieldChange = useCallback(
    (fieldName: string, value: unknown) => {
      setFormData((prev) => ({ ...prev, [fieldName]: value }));

      const shouldValidateOnChange =
        !!touched[fieldName] || validationMode === "change";
      if (shouldValidateOnChange && validationSchema[fieldName]) {
        const timers = changeTimersRef.current;
        if (timers[fieldName]) clearTimeout(timers[fieldName]);
        timers[fieldName] = setTimeout(() => {
          const schema = validationSchema[fieldName];
          if (schema) validateFieldValue(fieldName, value, schema);
          timers[fieldName] = undefined;
        }, 400);
      }
    },
    [touched, validationMode, validationSchema, validateFieldValue],
  );

  const handleFieldBlur = useCallback(
    (fieldName: string) => {
      setTouched((prev) => ({ ...prev, [fieldName]: true }));
      const schema = validationSchema[fieldName];
      if (schema) {
        const value = formData[fieldName];
        validateFieldValue(fieldName, value, schema);
      }
    },
    [validationSchema, formData, validateFieldValue],
  );

  const handleSubmit = useCallback(
    async (event: React.FormEvent<HTMLFormElement>) => {
      event.preventDefault();
      setIsSubmitting(true);

      const formErrors = validateForm(formData, validationSchema);
      setErrors(formErrors);
      const hasErrors = Object.keys(formErrors).some(
        (k) => formErrors[k] !== null,
      );
      if (hasErrors) {
        const allTouched: FormTouched = {};
        Object.keys(validationSchema).forEach((fieldName) => {
          allTouched[fieldName] = true;
        });
        setTouched(allTouched);
        setIsSubmitting(false);
        onError?.(formErrors);
        return;
      }

      try {
        await onSubmit(formData);
      } catch (e) {
        const message = e instanceof Error ? e.message : "Submit failed";
        onError?.({ submit: message });
      } finally {
        setIsSubmitting(false);
      }
    },
    [formData, validationSchema, onSubmit, onError],
  );

  const reset = useCallback((nextValues?: Record<string, unknown>) => {
    const values =
      nextValues && typeof nextValues === "object"
        ? nextValues
        : initialValuesRef.current || {};
    setFormData(values);
    setErrors({});
    setTouched({});
    setIsSubmitting(false);
  }, []);

  useImperativeHandle(ref, () => ({ reset }), [reset]);

  useEffect(() => {
    if (validateOnMount && Object.keys(validationSchema).length > 0) {
      const formErrors = validateForm(formData, validationSchema);
      setErrors(formErrors);
    }
  }, [validateOnMount, validationSchema, formData]);

  const ctx: FormContextValue = {
    formData,
    errors,
    touched,
    isSubmitting,
    disableAutofill,
    validationMode,
    showErrorsOn,
    validationSchema,
    registerField,
    unregisterField,
    validateFieldValue,
    handleFieldChange,
    handleFieldBlur,
    getUniqueFieldName,
    setFormData,
    setErrors,
    setTouched,
  };

  return (
    <FormContext.Provider value={ctx}>
      <form
        onSubmit={handleSubmit}
        className={className}
        noValidate
        autoComplete={resolvedAutoComplete}
        {...restFormProps}
      >
        {disableAutofill ? (
          <>
            <input
              tabIndex={-1}
              aria-hidden="true"
              type="text"
              name="__oks_autofill_username"
              autoComplete="username"
              style={{
                position: "absolute",
                top: 0,
                left: -9999,
                width: 1,
                height: 1,
                opacity: 0,
                pointerEvents: "none",
              }}
            />
            <input
              tabIndex={-1}
              aria-hidden="true"
              type="password"
              name="__oks_autofill_password"
              autoComplete="new-password"
              style={{
                position: "absolute",
                top: 0,
                left: -9999,
                width: 1,
                height: 1,
                opacity: 0,
                pointerEvents: "none",
              }}
            />
          </>
        ) : null}
        {children}
      </form>
    </FormContext.Provider>
  );
});

Form.displayName = "Form";
