import type { CSSProperties, InputHTMLAttributes, ReactNode } from "react";
import { forwardRef, useId, useMemo, useState } from "react";
import type {
  FormElementLabelPlacement,
  FormElementSize,
  FormElementTone,
  FormElementVariant,
} from "../types";
import { getToneVar, mergeClassName } from "../internal";
import type { ValidationRules } from "../../Validation";
import { evaluateStrongPassword } from "../../Validation";
import {
  EyeIcon,
  EyeOffIcon,
  StatusIcon,
} from "../../../../internal/icons/StatusIcons";
import "./PasswordField.module.css";
import "../TextField/TextField.module.css";

export type PasswordFieldSize = FormElementSize;

export type PasswordFieldVariant = FormElementVariant;

export type PasswordFieldTone = FormElementTone;

export type PasswordFieldLabelPlacement = FormElementLabelPlacement;

export type PasswordFieldRadius = "none" | "sm" | "md" | "lg" | "full";

export type PasswordFieldProps = Omit<
  InputHTMLAttributes<HTMLInputElement>,
  "size" | "color" | "type"
> & {
  label?: ReactNode;
  labelPlacement?: PasswordFieldLabelPlacement;
  description?: ReactNode;
  error?: ReactNode | boolean;
  size?: PasswordFieldSize;
  variant?: PasswordFieldVariant;
  color?: PasswordFieldTone;
  tone?: PasswordFieldTone;
  colorDepth?: number;
  radius?: PasswordFieldRadius;
  rounded?: PasswordFieldRadius;
  startIcon?: ReactNode;
  endIcon?: ReactNode;
  prefix?: ReactNode;
  suffix?: ReactNode;
  style?: CSSProperties;
  strongPassword?: ValidationRules["strongPassword"];
  revealToggle?: boolean;
};

const plural = (n: number, word: string) => (n === 1 ? word : `${word}s`);

export const PasswordField = forwardRef<HTMLInputElement, PasswordFieldProps>(
  (props, ref) => {
    const {
      label,
      labelPlacement = "top",
      description,
      error,
      size = "md",
      variant = "outline",
      color,
      tone,
      colorDepth = 500,
      radius,
      rounded,
      startIcon,
      endIcon,
      prefix,
      suffix,
      className,
      id,
      required,
      disabled,
      placeholder,
      style,
      value,
      defaultValue,
      onFocus,
      onBlur,
      strongPassword,
      revealToggle = true,
      ...rest
    } = props;

    const resolvedColor = color ?? tone ?? "default";
    const resolvedRadius = radius ?? rounded ?? "md";

    const reactId = useId();
    const inputId = id ?? `oks-password-field-${reactId}`;

    const [revealed, setRevealed] = useState(false);
    const [focused, setFocused] = useState(false);

    const describedBy = rest["aria-describedby"];
    const descriptionId = description ? `${inputId}-description` : undefined;
    const errorId =
      error && error !== true ? `${inputId}-error-message` : undefined;
    const requirementsId = `${inputId}-requirements`;
    const shouldShowRequirements =
      Boolean(strongPassword) && focused;
    const ariaDescribedBy = [
      describedBy,
      descriptionId,
      shouldShowRequirements ? requirementsId : undefined,
      shouldShowRequirements ? undefined : errorId,
    ]
      .filter(Boolean)
      .join(" ");

    const isInvalid = Boolean(error);

    const resolvedPlaceholder = useMemo(() => {
      if (labelPlacement !== "floating") return placeholder;
      if (!label) return placeholder;
      if (placeholder !== undefined) return placeholder;
      return " ";
    }, [labelPlacement, label, placeholder]);

    const toneVars: CSSProperties = {
      "--oks-text-field-tone": getToneVar(resolvedColor, colorDepth),
    } as unknown as CSSProperties;

    const topLabel = labelPlacement === "top" ? label : null;
    const floatingLabel = labelPlacement === "floating" ? label : null;

    const hasStart = startIcon != null || prefix != null;
    const hasEnd = endIcon != null || suffix != null || revealToggle;

    const evalResult = useMemo(() => {
      if (!strongPassword) return null;
      const v =
        value !== undefined
          ? String(value ?? "")
          : defaultValue !== undefined
            ? String(defaultValue ?? "")
            : "";
      return evaluateStrongPassword(v, strongPassword);
    }, [value, defaultValue, strongPassword]);

    const requirementRows = useMemo(() => {
      const rows: Array<{ key: string; met: boolean; label: string }> = [];
      if (strongPassword && evalResult) {
        const minLength =
          typeof strongPassword.minLength === "number" ? strongPassword.minLength : 8;
        const minUpper =
          typeof strongPassword.minUpper === "number" ? strongPassword.minUpper : 1;
        const minLower =
          typeof strongPassword.minLower === "number" ? strongPassword.minLower : 1;
        const minNumber =
          typeof strongPassword.minNumber === "number" ? strongPassword.minNumber : 1;
        const minSpecial =
          typeof strongPassword.minSpecial === "number" ? strongPassword.minSpecial : 1;

        if (minNumber > 0) {
          rows.push({
            key: "number",
            met: evalResult.numberOk,
            label: `At least ${minNumber} ${plural(minNumber, "number")}`,
          });
        }
        if (minUpper > 0) {
          rows.unshift({
            key: "upper",
            met: evalResult.upperOk,
            label: `At least ${minUpper} uppercase ${plural(minUpper, "letter")}`,
          });
        }
        if (minSpecial > 0) {
          rows.push({
            key: "special",
            met: evalResult.specialOk,
            label: `At least ${minSpecial} special ${plural(minSpecial, "character")}`,
          });
        }
        if (minLength > 0) {
          rows.push({
            key: "length",
            met: evalResult.minLengthOk,
            label: `At least ${minLength} ${plural(minLength, "character")}`,
          });
        }
        if (minLower > 0) {
          rows.push({
            key: "lower",
            met: evalResult.lowerOk,
            label: `At least ${minLower} lowercase ${plural(minLower, "letter")}`,
          });
        }
      }
      return rows;
    }, [strongPassword, evalResult]);

    const requirementsTitle = useMemo(() => {
      if (!strongPassword) return null;
      if (evalResult)
        return evalResult.ok ? "Strong password." : "Weak password. Must contain;";
      return "Must contain;";
    }, [strongPassword, evalResult]);

    return (
      <div
        className={mergeClassName("oksTextField oksPasswordField", className)}
        data-size={size}
        data-variant={variant}
        data-color={resolvedColor}
        data-radius={resolvedRadius}
        data-label-placement={labelPlacement}
        data-invalid={isInvalid ? "true" : "false"}
        data-disabled={disabled ? "true" : "false"}
        data-has-start={hasStart ? "true" : "false"}
        data-has-end={hasEnd ? "true" : "false"}
        style={{ ...toneVars, ...style }}
      >
        {topLabel ? (
          <label className="oksTextFieldLabel" htmlFor={inputId}>
            {topLabel}
            {required ? <span aria-hidden="true">*</span> : null}
          </label>
        ) : null}

        <div
          className="oksTextFieldControl"
          onFocusCapture={() => setFocused(true)}
          onBlurCapture={(e) => {
            const next = (e.relatedTarget as Node | null) ?? null;
            if (next && e.currentTarget.contains(next)) return;
            setFocused(false);
          }}
        >
          {hasStart ? (
            <span className="oksTextFieldAdornment oksTextFieldStart">
              {startIcon != null ? (
                <span className="oksTextFieldIcon">{startIcon}</span>
              ) : null}
              {prefix != null ? (
                <span className="oksTextFieldAffix">{prefix}</span>
              ) : null}
            </span>
          ) : null}

          <div className="oksTextFieldInputSlot">
            <input
              {...rest}
              ref={ref}
              id={inputId}
              required={required}
              disabled={disabled}
              type={revealed ? "text" : "password"}
              value={value as any}
              defaultValue={defaultValue as any}
              placeholder={resolvedPlaceholder}
              className="oksTextFieldInput"
              aria-invalid={isInvalid ? "true" : undefined}
              aria-describedby={ariaDescribedBy || undefined}
              aria-errormessage={shouldShowRequirements ? undefined : errorId}
              onFocus={(e) => {
                onFocus?.(e);
              }}
              onBlur={(e) => {
                onBlur?.(e);
              }}
            />

            {floatingLabel ? (
              <label className="oksTextFieldLabel" htmlFor={inputId}>
                {floatingLabel}
                {required ? <span aria-hidden="true">*</span> : null}
              </label>
            ) : null}
          </div>

          {hasEnd ? (
            <span className="oksTextFieldAdornment oksTextFieldEnd">
              {suffix != null ? (
                <span className="oksTextFieldAffix">{suffix}</span>
              ) : null}
              {endIcon != null ? (
                <span className="oksTextFieldIcon">{endIcon}</span>
              ) : null}
              {revealToggle ? (
                <button
                  type="button"
                  className="oksPasswordFieldRevealButton"
                  aria-label={revealed ? "Hide password" : "Show password"}
                  aria-pressed={revealed}
                  disabled={disabled}
                  tabIndex={disabled ? -1 : 0}
                  onClick={() => setRevealed((v) => !v)}
                >
                  {revealed ? <EyeOffIcon /> : <EyeIcon />}
                </button>
              ) : null}
            </span>
          ) : null}

          {shouldShowRequirements && requirementRows.length > 0 ? (
            <div id={requirementsId} className="oksPasswordFieldRequirements">
              {requirementsTitle ? (
                <div className="oksPasswordFieldRequirementsTitle">
                  {requirementsTitle}
                </div>
              ) : null}
              <ul className="oksPasswordFieldRequirementsList">
                {requirementRows.map((row) => (
                  <li
                    key={row.key}
                    className="oksPasswordFieldRequirement"
                    data-met={row.met ? "true" : "false"}
                  >
                    <span
                      className="oksPasswordFieldRequirementIcon"
                      aria-hidden="true"
                    >
                      <StatusIcon type={row.met ? "success" : "error"} />
                    </span>
                    <span>{row.label}</span>
                  </li>
                ))}
              </ul>
            </div>
          ) : null}
        </div>

        {description ? (
          <div id={descriptionId} className="oksTextFieldDescription">
            {description}
          </div>
        ) : null}

        {shouldShowRequirements ? null : error && error !== true ? (
          <div id={errorId} className="oksTextFieldError" role="alert">
            {error}
          </div>
        ) : null}
      </div>
    );
  },
);

PasswordField.displayName = "PasswordField";
