import type { CSSProperties, InputHTMLAttributes, ReactNode } from "react";
import { forwardRef, useId } from "react";
import type {
  FormElementLabelPlacement,
  FormElementSize,
  FormElementTone,
} from "../types";
import { getToneVar, mergeClassName } from "../internal";
import "./SwitchField.module.css";

export type SwitchFieldProps = Omit<
  InputHTMLAttributes<HTMLInputElement>,
  "type" | "size" | "color" | "checked" | "defaultChecked" | "onChange"
> & {
  label?: ReactNode;
  labelPlacement?: FormElementLabelPlacement;
  description?: ReactNode;
  error?: ReactNode | boolean;
  size?: FormElementSize;
  tone?: FormElementTone;
  colorDepth?: number;
  checked?: boolean;
  defaultChecked?: boolean;
  onChange?: (next: boolean) => void;
  showStateText?: boolean;
  checkedText?: ReactNode;
  uncheckedText?: ReactNode;
  stateTextPlacement?: "before" | "after" | "both";
  style?: CSSProperties;
};

export const SwitchField = forwardRef<HTMLLabelElement, SwitchFieldProps>(
  (props, ref) => {
    const {
      label,
      labelPlacement = "top",
      description,
      error,
      size = "md",
      tone = "primary",
      colorDepth = 500,
      className,
      id,
      required,
      disabled,
      checked,
      defaultChecked,
      onChange,
      showStateText = false,
      checkedText = "On",
      uncheckedText = "Off",
      stateTextPlacement = "after",
      style,
      ...rest
    } = props;

    const reactId = useId();
    const switchId = id ?? `oks-switch-${reactId}`;

    const resolvedLabelPlacement =
      labelPlacement === "floating" ? "top" : labelPlacement;

    const descriptionId = description ? `${switchId}-description` : undefined;
    const errorId =
      error && error !== true ? `${switchId}-error-message` : undefined;
    const ariaDescribedBy = [descriptionId, errorId].filter(Boolean).join(" ");
    const isInvalid = Boolean(error);

    const toneVars: CSSProperties = {
      "--oks-switch-tone": getToneVar(tone, colorDepth),
    } as unknown as CSSProperties;

    return (
      <div
        className={mergeClassName("oksSwitchField", className)}
        data-size={size}
        data-tone={tone}
        data-label-placement={resolvedLabelPlacement}
        data-invalid={isInvalid ? "true" : "false"}
        data-disabled={disabled ? "true" : "false"}
        style={{ ...toneVars, ...style }}
      >
        <label ref={ref} className="oksSwitchFieldRow" htmlFor={switchId}>
          {resolvedLabelPlacement === "top" && label ? (
            <span className="oksSwitchFieldLabel">
              {label}
              {required ? <span aria-hidden="true">*</span> : null}
            </span>
          ) : null}

          <span className="oksSwitchFieldControl">
            <input
              {...rest}
              id={switchId}
              type="checkbox"
              role="switch"
              required={required}
              disabled={disabled}
              checked={checked}
              defaultChecked={defaultChecked}
              onChange={(e) => onChange?.(e.currentTarget.checked)}
              className="oksSwitchFieldInput"
              aria-invalid={isInvalid ? "true" : undefined}
              aria-describedby={ariaDescribedBy || undefined}
              aria-errormessage={errorId}
            />
            <span
              className="oksSwitchFieldControlInner"
              data-state-text-placement={stateTextPlacement}
            >
              <span className="oksSwitchFieldTrack" aria-hidden="true">
                <span className="oksSwitchFieldThumb" />
              </span>
              {showStateText ? (
                <>
                  <span
                    className="oksSwitchFieldStateText"
                    data-state="unchecked"
                  >
                    {uncheckedText}
                  </span>
                  <span className="oksSwitchFieldStateText" data-state="checked">
                    {checkedText}
                  </span>
                </>
              ) : null}
            </span>
          </span>

          {resolvedLabelPlacement !== "top" && label ? (
            <span className="oksSwitchFieldLabel">
              {label}
              {required ? <span aria-hidden="true">*</span> : null}
            </span>
          ) : null}
        </label>

        {description ? (
          <div id={descriptionId} className="oksSwitchFieldDescription">
            {description}
          </div>
        ) : null}

        {error && error !== true ? (
          <div id={errorId} className="oksSwitchFieldError" role="alert">
            {error}
          </div>
        ) : null}
      </div>
    );
  },
);

SwitchField.displayName = "SwitchField";
