import type { CSSProperties, ReactNode } from "react";
import { forwardRef, useEffect, useId, useState } from "react";
import type { FormElementSize, FormElementTone } from "../types";
import { getToneVar, mergeClassName } from "../internal";
import "./RadioGroupField.module.css";

export type RadioOption = {
  label: ReactNode;
  value: string;
  disabled?: boolean;
  key?: string;
};

export type RadioGroupFieldProps = {
  label?: ReactNode;
  description?: ReactNode;
  error?: ReactNode | boolean;
  size?: FormElementSize;
  tone?: FormElementTone;
  colorDepth?: number;
  name?: string;
  id?: string;
  required?: boolean;
  disabled?: boolean;
  options: RadioOption[];
  value?: string;
  defaultValue?: string;
  onChange?: (next: string) => void;
  className?: string;
  style?: CSSProperties;
};

export const RadioGroupField = forwardRef<HTMLDivElement, RadioGroupFieldProps>(
  (props, ref) => {
    const {
      label,
      description,
      error,
      size = "md",
      tone = "primary",
      colorDepth = 500,
      className,
      id,
      name,
      required,
      disabled,
      options,
      value,
      defaultValue,
      onChange,
      style,
    } = props;

    const reactId = useId();
    const groupId = id ?? `oks-radio-group-${reactId}`;
    const groupName = name ?? groupId;

    const descriptionId = description ? `${groupId}-description` : undefined;
    const errorId =
      error && error !== true ? `${groupId}-error-message` : undefined;
    const ariaDescribedBy = [descriptionId, errorId].filter(Boolean).join(" ");

    const isInvalid = Boolean(error);
    const isControlled = value !== undefined;
    const [internalValue, setInternalValue] = useState<string>(
      () => defaultValue ?? "",
    );

    useEffect(() => {
      if (!isControlled) return;
      setInternalValue(value ?? "");
    }, [isControlled, value]);

    const selected = isControlled ? String(value ?? "") : internalValue;

    const toneVars: CSSProperties = {
      "--oks-radio-tone": getToneVar(tone, colorDepth),
    } as unknown as CSSProperties;

    return (
      <div
        ref={ref}
        className={mergeClassName("oksRadioGroupField", className)}
        data-size={size}
        data-tone={tone}
        data-invalid={isInvalid ? "true" : "false"}
        data-disabled={disabled ? "true" : "false"}
        style={{ ...toneVars, ...style }}
      >
        {label ? (
          <div className="oksRadioGroupFieldLabel">
            {label}
            {required ? <span aria-hidden="true">*</span> : null}
          </div>
        ) : null}

        <div role="radiogroup" aria-describedby={ariaDescribedBy || undefined}>
          <div className="oksRadioGroupFieldItems">
            {options.map((opt, idx) => {
              const optionId = `${groupId}-${opt.key ?? `${idx}-${opt.value}`}`;
              const isDisabled = disabled || opt.disabled;
              const checked = String(selected) === opt.value;
              return (
                <label
                  key={opt.key ?? `${idx}-${opt.value}`}
                  className="oksRadioGroupFieldItem"
                  data-disabled={isDisabled ? "true" : "false"}
                >
                  <input
                    id={optionId}
                    type="radio"
                    name={groupName}
                    disabled={isDisabled}
                    value={opt.value}
                    checked={checked}
                    onChange={() => {
                      if (isDisabled) return;
                      if (!isControlled) setInternalValue(opt.value);
                      onChange?.(opt.value);
                    }}
                    className="oksRadioGroupFieldInput"
                    aria-invalid={isInvalid ? "true" : undefined}
                  />
                  <span className="oksRadioGroupFieldItemLabel">{opt.label}</span>
                </label>
              );
            })}
          </div>
        </div>

        {description ? (
          <div id={descriptionId} className="oksRadioGroupFieldDescription">
            {description}
          </div>
        ) : null}

        {error && error !== true ? (
          <div id={errorId} className="oksRadioGroupFieldError" role="alert">
            {error}
          </div>
        ) : null}
      </div>
    );
  },
);

RadioGroupField.displayName = "RadioGroupField";

