import type { CSSProperties, InputHTMLAttributes, ReactNode } from "react";
import { forwardRef, useId, useMemo } from "react";
import type {
  FormElementLabelPlacement,
  FormElementSize,
  FormElementTone,
  FormElementVariant,
} from "../types";
import { getToneVar, mergeClassName } from "../internal";
import "./TextField.module.css";

export type TextFieldSize = FormElementSize;

export type TextFieldVariant = FormElementVariant;

export type TextFieldTone = FormElementTone;

export type TextFieldLabelPlacement = FormElementLabelPlacement;

export type TextFieldRadius = "none" | "sm" | "md" | "lg" | "full";

export type TextFieldProps = Omit<
  InputHTMLAttributes<HTMLInputElement>,
  "size" | "color"
> & {
  label?: ReactNode;
  labelPlacement?: TextFieldLabelPlacement;
  description?: ReactNode;
  error?: ReactNode | boolean;
  size?: TextFieldSize;
  variant?: TextFieldVariant;
  color?: TextFieldTone;
  tone?: TextFieldTone;
  colorDepth?: number;
  radius?: TextFieldRadius;
  rounded?: TextFieldRadius;
  startIcon?: ReactNode;
  endIcon?: ReactNode;
  prefix?: ReactNode;
  suffix?: ReactNode;
  style?: CSSProperties;
};

export const TextField = forwardRef<HTMLInputElement, TextFieldProps>(
  (props, ref) => {
    const {
      label,
      labelPlacement = "top",
      description,
      error,
      size = "md",
      variant = "outline",
      color,
      tone,
      colorDepth = 500,
      radius,
      rounded,
      startIcon,
      endIcon,
      prefix,
      suffix,
      className,
      id,
      required,
      disabled,
      placeholder,
      style,
      ...rest
    } = props;

    const resolvedColor = color ?? tone ?? "default";
    const resolvedRadius = radius ?? rounded ?? "md";

    const reactId = useId();
    const inputId = id ?? `oks-text-field-${reactId}`;

    const describedBy = rest["aria-describedby"];
    const descriptionId = description ? `${inputId}-description` : undefined;
    const errorId =
      error && error !== true ? `${inputId}-error-message` : undefined;
    const ariaDescribedBy = [describedBy, descriptionId, errorId]
      .filter(Boolean)
      .join(" ");

    const isInvalid = Boolean(error);

    const resolvedPlaceholder = useMemo(() => {
      if (labelPlacement !== "floating") return placeholder;
      if (!label) return placeholder;
      if (placeholder !== undefined) return placeholder;
      return " ";
    }, [labelPlacement, label, placeholder]);

    const toneVars: CSSProperties = {
      "--oks-text-field-tone": getToneVar(resolvedColor, colorDepth),
    } as unknown as CSSProperties;

    const topLabel = labelPlacement === "top" ? label : null;
    const floatingLabel = labelPlacement === "floating" ? label : null;

    const hasStart = startIcon != null || prefix != null;
    const hasEnd = endIcon != null || suffix != null;

    return (
      <div
        className={mergeClassName("oksTextField", className)}
        data-size={size}
        data-variant={variant}
        data-color={resolvedColor}
        data-radius={resolvedRadius}
        data-label-placement={labelPlacement}
        data-invalid={isInvalid ? "true" : "false"}
        data-disabled={disabled ? "true" : "false"}
        data-has-start={hasStart ? "true" : "false"}
        data-has-end={hasEnd ? "true" : "false"}
        style={{ ...toneVars, ...style }}
      >
        {topLabel ? (
          <label className="oksTextFieldLabel" htmlFor={inputId}>
            {topLabel}
            {required ? <span aria-hidden="true">*</span> : null}
          </label>
        ) : null}

        <div className="oksTextFieldControl">
          {hasStart ? (
            <span className="oksTextFieldAdornment oksTextFieldStart">
              {startIcon != null ? (
                <span className="oksTextFieldIcon">{startIcon}</span>
              ) : null}
              {prefix != null ? (
                <span className="oksTextFieldAffix">{prefix}</span>
              ) : null}
            </span>
          ) : null}

          <div className="oksTextFieldInputSlot">
            <input
              {...rest}
              ref={ref}
              id={inputId}
              required={required}
              disabled={disabled}
              placeholder={resolvedPlaceholder}
              className="oksTextFieldInput"
              aria-invalid={isInvalid ? "true" : undefined}
              aria-describedby={ariaDescribedBy || undefined}
              aria-errormessage={errorId}
            />

            {floatingLabel ? (
              <label className="oksTextFieldLabel" htmlFor={inputId}>
                {floatingLabel}
                {required ? <span aria-hidden="true">*</span> : null}
              </label>
            ) : null}
          </div>

          {hasEnd ? (
            <span className="oksTextFieldAdornment oksTextFieldEnd">
              {suffix != null ? (
                <span className="oksTextFieldAffix">{suffix}</span>
              ) : null}
              {endIcon != null ? (
                <span className="oksTextFieldIcon">{endIcon}</span>
              ) : null}
            </span>
          ) : null}
        </div>

        {description ? (
          <div id={descriptionId} className="oksTextFieldDescription">
            {description}
          </div>
        ) : null}

        {error && error !== true ? (
          <div id={errorId} className="oksTextFieldError" role="alert">
            {error}
          </div>
        ) : null}
      </div>
    );
  },
);

TextField.displayName = "TextField";
