import type { CSSProperties, HTMLAttributes, ReactNode } from "react";
import { forwardRef } from "react";
import { clamp } from "../../utils";
import "./Divider.module.css";

export type DividerOrientation = "horizontal" | "vertical";

export type DividerVariant = "fullWidth" | "inset" | "middle";

export type DividerColor =
  | "default"
  | "primary"
  | "info"
  | "success"
  | "warning"
  | "danger"
  | "secondary"
  | (string & {});

export type DividerColorDepth =
  | 50
  | 100
  | 200
  | 300
  | 400
  | 500
  | 600
  | 700
  | 800
  | 900
  | 950;

export type DividerProps = Omit<
  HTMLAttributes<HTMLElement>,
  "color" | "children"
> & {
  orientation?: DividerOrientation;
  variant?: DividerVariant;
  color?: DividerColor;
  colorDepth?: DividerColorDepth;
  thickness?: number | string;
  children?: ReactNode;
};

function mergeClassName(a: unknown, b: unknown) {
  const sa = typeof a === "string" ? a : "";
  const sb = typeof b === "string" ? b : "";
  return [sa, sb].filter(Boolean).join(" ");
}

const ALLOWED_DEPTHS = [
  50, 100, 200, 300, 400, 500, 600, 700, 800, 900, 950,
] as const;

function snapDepth(input: number) {
  const clamped = clamp(input, 50, 950);
  const first: number = ALLOWED_DEPTHS[0] ?? 500;
  let best: number = first;
  let bestDiff = Math.abs(best - clamped);
  for (const d of ALLOWED_DEPTHS) {
    const diff = Math.abs(d - clamped);
    if (diff < bestDiff) {
      best = d;
      bestDiff = diff;
    }
  }
  return best;
}

function getColorVar(color: string, depth: number) {
  const fallback = `var(--oks-color-default-${depth}, var(--oks-color-primary-${depth}, #d1d5db))`;
  if (color === "default") return fallback;
  return `var(--oks-color-${color}-${depth}, ${fallback})`;
}

export const Divider = forwardRef<HTMLHRElement | HTMLDivElement, DividerProps>(
  (props, ref) => {
    const {
      orientation = "horizontal",
      variant = "fullWidth",
      color,
      colorDepth = 300,
      thickness,
      children,
      className,
      style,
      ...rest
    } = props;

    const resolvedColor = (color ?? "primary") as string;
    const resolvedDepth =
      typeof colorDepth === "number" ? snapDepth(colorDepth) : 300;

    const thicknessVar: CSSProperties =
      thickness !== undefined
        ? ({
            ["--oks-divider-thickness" as any]:
              typeof thickness === "number" ? `${thickness}px` : thickness,
          } as unknown as CSSProperties)
        : ({} as CSSProperties);

    const dividerVars: CSSProperties = {
      ["--oks-divider-border" as any]: getColorVar(
        resolvedColor,
        resolvedDepth,
      ),
      ...thicknessVar,
    } as unknown as CSSProperties;

    const ariaLabel = rest["aria-label"];
    const resolvedAriaLabel =
      typeof ariaLabel === "string"
        ? ariaLabel
        : typeof children === "string"
          ? children
          : undefined;

    const rootStyle: CSSProperties = {
      ...dividerVars,
      ...(style ?? {}),
    };

    const rootClassName = mergeClassName(
      children && orientation === "horizontal"
        ? "oksDivider oksDividerWithText"
        : "oksDivider",
      className,
    );

    if (orientation === "vertical") {
      return (
        <div
          {...rest}
          role="separator"
          aria-orientation="vertical"
          aria-label={resolvedAriaLabel}
          ref={ref as any}
          className={rootClassName}
          data-orientation="vertical"
          data-variant={variant}
          data-color={resolvedColor}
          style={rootStyle}
        />
      );
    }

    if (children) {
      return (
        <div
          {...rest}
          role="separator"
          aria-orientation="horizontal"
          aria-label={resolvedAriaLabel}
          ref={ref as any}
          className={rootClassName}
          data-orientation="horizontal"
          data-variant={variant}
          data-color={resolvedColor}
          style={rootStyle}
        >
          <span className="oksDividerLine" aria-hidden="true" />
          <span className="oksDividerLabel">{children}</span>
          <span className="oksDividerLine" aria-hidden="true" />
        </div>
      );
    }

    return (
      <hr
        {...rest}
        role="separator"
        aria-orientation="horizontal"
        aria-label={resolvedAriaLabel}
        ref={ref as any}
        className={rootClassName}
        data-orientation="horizontal"
        data-variant={variant}
        data-color={resolvedColor}
        style={rootStyle}
      />
    );
  },
);

Divider.displayName = "Divider";
