export type ValidationRuleName =
  | "required"
  | "email"
  | "minLength"
  | "maxLength"
  | "pattern"
  | "alpha"
  | "alphanumeric"
  | "numeric"
  | "min"
  | "max"
  | "strongPassword"
  | "matchField"
  | "accept"
  | "maxFileSize"
  | "maxFiles"
  | "custom";

export type DefaultValidationMessage = string | ((arg: any) => string);

export type ValidationContext = {
  formData?: Record<string, unknown>;
  fieldName?: string;
};

export const DEFAULT_VALIDATION_MESSAGES: Record<
  Exclude<ValidationRuleName, "custom">,
  DefaultValidationMessage
> = {
  required: "This field is required",
  email: "Please enter a valid email address",
  minLength: (min) => `Must be at least ${min} characters`,
  maxLength: (max) => `Must be no more than ${max} characters`,
  pattern: "Please match the required format",
  alpha: "Only letters are allowed",
  alphanumeric: "Only letters and numbers are allowed",
  numeric: "Please enter a valid number",
  min: (min) => `Must be at least ${min}`,
  max: (max) => `Must be no more than ${max}`,
  strongPassword: "Weak password. Must contain required items.",
  matchField: "Fields do not match",
  accept: "Unsupported file type",
  maxFileSize: (maxBytes) => `File must be ${maxBytes} bytes or less`,
  maxFiles: (maxFiles) => `Must select no more than ${maxFiles} files`,
};

const digitsOnly = (s: unknown) => String(s ?? "").replace(/\D+/g, "");

type PhoneParts = { code: string; phone: string };

const getPhoneParts = (value: unknown): PhoneParts | null => {
  if (Array.isArray(value) && value.length > 0) {
    const first = value[0] as unknown;
    if (first && typeof first === "object") {
      const obj = first as any;
      return { code: obj.code ?? "", phone: obj.phone ?? "" };
    }
    return null;
  }
  if (value && typeof value === "object") {
    const obj = value as any;
    if ("phone" in obj || "code" in obj) {
      return { code: obj.code ?? "", phone: obj.phone ?? "" };
    }
  }
  return null;
};

type DateRangeParts = { start: string; end: string };

const getDateRangeParts = (value: unknown): DateRangeParts | null => {
  if (value && typeof value === "object") {
    const obj = value as any;
    if ("start" in obj || "end" in obj) {
      return { start: obj.start ?? "", end: obj.end ?? "" };
    }
  }
  return null;
};

const isFileList = (value: unknown): value is FileList => {
  if (typeof FileList === "undefined") return false;
  return value instanceof FileList;
};

const isFile = (value: unknown): value is File => {
  if (typeof File === "undefined") return false;
  return value instanceof File;
};

const getFiles = (value: unknown): File[] => {
  if (!value) return [];
  if (isFile(value)) return [value];
  if (isFileList(value)) return Array.from(value);
  if (Array.isArray(value) && value.every((v) => isFile(v)))
    return value as File[];
  return [];
};

const getValueByPath = (obj: Record<string, unknown>, path: string) => {
  if (!path) return undefined;
  if (Object.prototype.hasOwnProperty.call(obj, path))
    return (obj as any)[path];
  const parts = path.split(".").filter(Boolean);
  let cur: any = obj;
  for (const p of parts) {
    if (!cur || typeof cur !== "object") return undefined;
    cur = cur[p];
  }
  return cur;
};

const parseAccept = (accept: string | string[]) => {
  const raw = Array.isArray(accept) ? accept.join(",") : accept;
  return raw
    .split(",")
    .map((s) => s.trim())
    .filter(Boolean);
};

const matchesAcceptToken = (file: File, token: string) => {
  const lowerToken = token.toLowerCase();
  if (lowerToken.startsWith(".")) {
    return file.name.toLowerCase().endsWith(lowerToken);
  }
  if (lowerToken.endsWith("/*")) {
    const prefix = lowerToken.slice(0, -1);
    return file.type.toLowerCase().startsWith(prefix);
  }
  return file.type.toLowerCase() === lowerToken;
};

export type ValidationRules = Partial<{
  required: boolean;
  email: boolean;
  minLength: number;
  maxLength: number;
  pattern: RegExp;
  alpha: boolean;
  alphanumeric: boolean;
  numeric: boolean;
  min: number;
  max: number;
  strongPassword: {
    minLength?: number;
    minUpper?: number;
    minLower?: number;
    minNumber?: number;
    minSpecial?: number;
  };
  matchField: string;
  accept: string | string[];
  maxFileSize: number;
  maxFiles: number;
  custom: (value: unknown, ctx?: ValidationContext) => true | string | boolean;
}>;

export type ValidationMessages = Partial<Record<ValidationRuleName, string>>;

export type FieldValidation = {
  rules: ValidationRules;
  message?: ValidationMessages;
};

export type StrongPasswordConfig = NonNullable<
  ValidationRules["strongPassword"]
>;

export type StrongPasswordEvaluation = {
  ok: boolean;
  minLength: number;
  minUpper: number;
  minLower: number;
  minNumber: number;
  minSpecial: number;
  length: number;
  uppers: number;
  lowers: number;
  numbers: number;
  specials: number;
  minLengthOk: boolean;
  upperOk: boolean;
  lowerOk: boolean;
  numberOk: boolean;
  specialOk: boolean;
};

const normalizeStrongPasswordConfig = (
  config: ValidationRules["strongPassword"],
) => {
  const cfg = config && typeof config === "object" ? (config as any) : {};
  const minLength = typeof cfg.minLength === "number" ? cfg.minLength : 8;
  const minUpper = typeof cfg.minUpper === "number" ? cfg.minUpper : 1;
  const minLower = typeof cfg.minLower === "number" ? cfg.minLower : 1;
  const minNumber = typeof cfg.minNumber === "number" ? cfg.minNumber : 1;
  const minSpecial = typeof cfg.minSpecial === "number" ? cfg.minSpecial : 1;
  return { minLength, minUpper, minLower, minNumber, minSpecial };
};

export function evaluateStrongPassword(
  value: string,
  config: ValidationRules["strongPassword"],
): StrongPasswordEvaluation {
  const { minLength, minUpper, minLower, minNumber, minSpecial } =
    normalizeStrongPasswordConfig(config);
  const str = String(value ?? "");
  const length = str.length;
  const uppers = (str.match(/[A-Z]/g) || []).length;
  const lowers = (str.match(/[a-z]/g) || []).length;
  const numbers = (str.match(/[0-9]/g) || []).length;
  const specials = (str.match(/[^A-Za-z0-9]/g) || []).length;

  const minLengthOk = length >= minLength;
  const upperOk = uppers >= minUpper;
  const lowerOk = lowers >= minLower;
  const numberOk = numbers >= minNumber;
  const specialOk = specials >= minSpecial;

  const ok = minLengthOk && upperOk && lowerOk && numberOk && specialOk;

  return {
    ok,
    minLength,
    minUpper,
    minLower,
    minNumber,
    minSpecial,
    length,
    uppers,
    lowers,
    numbers,
    specials,
    minLengthOk,
    upperOk,
    lowerOk,
    numberOk,
    specialOk,
  };
}

export const VALIDATION_RULES: Record<
  Exclude<ValidationRuleName, "custom">,
  (value: unknown, arg?: any, ctx?: ValidationContext) => boolean
> = {
  required: (value) => {
    if (value === null || value === undefined) return false;
    if (typeof value === "string") return value.trim().length > 0;
    const phoneParts = getPhoneParts(value);
    if (phoneParts) return digitsOnly(phoneParts.phone).length > 0;
    const dateRangeParts = getDateRangeParts(value);
    if (dateRangeParts)
      return (
        String(dateRangeParts.start ?? "").trim().length > 0 &&
        String(dateRangeParts.end ?? "").trim().length > 0
      );
    const files = getFiles(value);
    if (files.length > 0) return true;
    if (isFileList(value)) return value.length > 0;
    if (Array.isArray(value)) return value.length > 0;
    if (typeof value === "boolean") return value === true;
    if (typeof value === "number") return Number.isFinite(value);
    return Boolean(value);
  },
  email: (value) => {
    if (!value) return true;
    return /^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/.test(String(value));
  },
  minLength: (value, min) => {
    if (!value) return true;
    const phoneParts = getPhoneParts(value);
    if (phoneParts) return digitsOnly(phoneParts.phone).length >= min;
    return String(value).length >= min;
  },
  maxLength: (value, max) => {
    if (!value) return true;
    const phoneParts = getPhoneParts(value);
    if (phoneParts) return digitsOnly(phoneParts.phone).length <= max;
    return String(value).length <= max;
  },
  pattern: (value, pattern) => {
    if (!value) return true;
    if (!(pattern instanceof RegExp)) return true;
    const phoneParts = getPhoneParts(value);
    if (phoneParts) {
      const phone = digitsOnly(phoneParts.phone);
      const code = String(phoneParts.code ?? "");
      const full = `${code}${phone}`;
      return pattern.test(full) || pattern.test(phone);
    }
    return pattern.test(String(value));
  },
  alpha: (value) => {
    if (!value) return true;
    return /^[A-Za-z]+$/.test(String(value));
  },
  alphanumeric: (value) => {
    if (!value) return true;
    return /^[A-Za-z0-9]+$/.test(String(value));
  },
  numeric: (value) => {
    if (!value) return true;
    const phoneParts = getPhoneParts(value);
    const raw = phoneParts ? digitsOnly(phoneParts.phone) : value;
    if (raw === "") return true;
    const num = Number(raw);
    return !Number.isNaN(num) && Number.isFinite(num);
  },
  min: (value, min) => {
    if (!value) return true;
    const phoneParts = getPhoneParts(value);
    const raw = phoneParts ? digitsOnly(phoneParts.phone) : value;
    if (raw === "") return true;
    const num = Number(raw);
    return !Number.isNaN(num) && Number.isFinite(num) && num >= min;
  },
  max: (value, max) => {
    if (!value) return true;
    const phoneParts = getPhoneParts(value);
    const raw = phoneParts ? digitsOnly(phoneParts.phone) : value;
    if (raw === "") return true;
    const num = Number(raw);
    return !Number.isNaN(num) && Number.isFinite(num) && num <= max;
  },
  strongPassword: (value, config) => {
    if (!value) return true;
    return evaluateStrongPassword(String(value), config).ok;
  },
  matchField: (value, otherFieldName, ctx) => {
    if (!ctx?.formData) return true;
    if (!otherFieldName || typeof otherFieldName !== "string") return true;
    const otherValue = getValueByPath(ctx.formData, otherFieldName);
    return value === otherValue;
  },
  accept: (value, accept) => {
    const files = getFiles(value);
    if (files.length < 1) return true;
    if (!accept) return true;
    const tokens = parseAccept(accept);
    if (tokens.length < 1) return true;
    return files.every((file) =>
      tokens.some((t) => matchesAcceptToken(file, t)),
    );
  },
  maxFileSize: (value, maxBytes) => {
    const files = getFiles(value);
    if (files.length < 1) return true;
    if (typeof maxBytes !== "number" || !Number.isFinite(maxBytes)) return true;
    return files.every((f) =>
      typeof f.size === "number" ? f.size <= maxBytes : true,
    );
  },
  maxFiles: (value, maxFiles) => {
    const files = getFiles(value);
    if (files.length < 1) return true;
    if (typeof maxFiles !== "number" || !Number.isFinite(maxFiles)) return true;
    return files.length <= maxFiles;
  },
};

export type ValidationErrors = Partial<Record<ValidationRuleName, string>>;

export function validateField(
  value: unknown,
  rules?: ValidationRules,
  customMessages: ValidationMessages = {},
  ctx?: ValidationContext,
): ValidationErrors {
  const errors: ValidationErrors = {};
  if (!rules) return errors;

  (Object.keys(rules) as ValidationRuleName[]).forEach((ruleName) => {
    const ruleValue = (rules as any)[ruleName];
    if (ruleValue === false || ruleValue === undefined) return;
    if (ruleName === "custom") return;

    const fn = (VALIDATION_RULES as any)[ruleName] as
      | ((v: unknown, arg?: unknown, ctx?: ValidationContext) => boolean)
      | undefined;
    if (!fn) return;

    const isValid = fn(value, ruleValue, ctx);
    if (isValid) return;

    const customMessage = customMessages[ruleName];
    if (typeof customMessage === "string" && customMessage.length > 0) {
      errors[ruleName] = customMessage;
      return;
    }

    const defaultMessage = (DEFAULT_VALIDATION_MESSAGES as any)[ruleName] as
      | DefaultValidationMessage
      | undefined;
    if (typeof defaultMessage === "function") {
      errors[ruleName] = defaultMessage(ruleValue);
      return;
    }
    errors[ruleName] =
      typeof defaultMessage === "string" && defaultMessage.length > 0
        ? defaultMessage
        : "Validation failed";
  });

  if (typeof rules.custom === "function") {
    const res = rules.custom(value, ctx);
    if (res !== true) {
      errors.custom =
        typeof res === "string"
          ? res
          : customMessages.custom || "Custom validation failed";
    }
  }

  return errors;
}

export function getFirstError(errors: ValidationErrors): string | null {
  const keys = Object.keys(errors);
  if (keys.length < 1) return null;
  const first = keys[0] as ValidationRuleName;
  return errors[first] ?? null;
}

export function validateForm(
  formData: Record<string, unknown>,
  validationSchema: Record<string, FieldValidation>,
): Record<string, string | null> {
  const formErrors: Record<string, string | null> = {};
  Object.keys(validationSchema).forEach((fieldName) => {
    const fieldValidation = validationSchema[fieldName];
    const value = formData[fieldName];
    const fieldErrors = validateField(
      value,
      fieldValidation?.rules,
      fieldValidation?.message ?? {},
      { formData, fieldName },
    );
    if (Object.keys(fieldErrors).length > 0) {
      formErrors[fieldName] = getFirstError(fieldErrors);
    }
  });
  return formErrors;
}
