import type { CSSProperties, HTMLAttributes, ReactNode } from "react";
import { forwardRef } from "react";
import type { PressEvent } from "../Button";
import { clamp } from "../../utils";
import "./Chip.module.css";

export type ChipVariant =
  | "solid"
  | "bordered"
  | "light"
  | "flat"
  | "faded"
  | "shadow"
  | "dot";

export type ChipSize = "sm" | "md" | "lg";

export type ChipColor =
  | "default"
  | "primary"
  | "secondary"
  | "success"
  | "warning"
  | "danger";

export type ChipRadius = "none" | "sm" | "md" | "lg" | "full";

export type ChipSlot = "base" | "content" | "dot" | "avatar" | "closeButton";

export type ChipColorDepth =
  | 50
  | 100
  | 200
  | 300
  | 400
  | 500
  | 600
  | 700
  | 800
  | 900
  | 950;

export type ChipProps = Omit<
  HTMLAttributes<HTMLDivElement>,
  "color" | "children"
> & {
  children?: ReactNode;
  variant?: ChipVariant;
  size?: ChipSize;
  color?: ChipColor;
  radius?: ChipRadius;
  colorDepth?: ChipColorDepth;
  avatar?: ReactNode;
  startContent?: ReactNode;
  endContent?: ReactNode;
  isDisabled?: boolean;
  onClose?: (e: PressEvent) => void;
  classNames?: Partial<Record<ChipSlot, string>>;
  style?: CSSProperties;
};

function mergeClassName(a: unknown, b: unknown) {
  const sa = typeof a === "string" ? a : "";
  const sb = typeof b === "string" ? b : "";
  return [sa, sb].filter(Boolean).join(" ");
}

const ALLOWED_DEPTHS = [
  50, 100, 200, 300, 400, 500, 600, 700, 800, 900, 950,
] as const;

function snapDepth(input: number) {
  const clamped = clamp(input, 50, 950);
  const first: number = ALLOWED_DEPTHS[0] ?? 500;
  let best: number = first;
  let bestDiff = Math.abs(best - clamped);
  for (const d of ALLOWED_DEPTHS) {
    const diff = Math.abs(d - clamped);
    if (diff < bestDiff) {
      best = d;
      bestDiff = diff;
    }
  }
  return best;
}

function getColorVar(color: string, depth: number) {
  const fallback = `var(--oks-color-default-${depth}, var(--oks-color-primary-${depth}, #3b82f6))`;
  if (color === "default") return fallback;
  return `var(--oks-color-${color}-${depth}, ${fallback})`;
}

export const Chip = forwardRef<HTMLDivElement, ChipProps>((props, ref) => {
  const {
    children,
    variant = "solid",
    size = "md",
    color = "default",
    radius = "full",
    colorDepth = 500,
    avatar,
    startContent,
    endContent,
    isDisabled = false,
    onClose,
    classNames,
    className,
    style,
    ...rest
  } = props;

  const resolvedDisabled = isDisabled;
  const resolvedDepth =
    typeof colorDepth === "number" ? snapDepth(colorDepth) : 500;
  const hoverDepth = snapDepth(resolvedDepth + 100);
  const activeDepth = snapDepth(resolvedDepth + 200);
  const solidFg = resolvedDepth <= 400 ? "#000" : "#fff";

  const chipToneVars: CSSProperties = {
    "--oks-chip-tone": getColorVar(color, resolvedDepth),
    "--oks-chip-tone-hover": getColorVar(color, hoverDepth),
    "--oks-chip-tone-active": getColorVar(color, activeDepth),
    "--oks-chip-tone-50": getColorVar(color, 50),
    "--oks-chip-tone-100": getColorVar(color, 100),
    "--oks-chip-tone-700": getColorVar(color, 700),
    "--oks-chip-solid-fg": solidFg,
  } as unknown as CSSProperties;

  const closeIcon = endContent ?? <span aria-hidden="true">×</span>;

  const closeButton =
    typeof onClose === "function" ? (
      <button
        type="button"
        className={mergeClassName("oksChipCloseButton", classNames?.closeButton)}
        aria-label="Close"
        disabled={resolvedDisabled}
        onClick={(e) => {
          e.stopPropagation();
          if (!resolvedDisabled) onClose(e as any);
        }}
      >
        {closeIcon}
      </button>
    ) : null;

  const chipElement = (
    <div
      {...rest}
      ref={ref}
      aria-disabled={resolvedDisabled ? "true" : undefined}
      data-variant={variant}
      data-size={size}
      data-color={color}
      data-radius={radius}
      data-disabled={resolvedDisabled ? "true" : "false"}
      className={mergeClassName(
        mergeClassName("oksChip", classNames?.base),
        className,
      )}
      style={{ ...chipToneVars, ...style }}
    >
      {variant === "dot" ? (
        <span
          className={mergeClassName("oksChipDot", classNames?.dot)}
          aria-hidden="true"
        />
      ) : null}
      {avatar !== undefined && avatar !== null ? (
        <span className={mergeClassName("oksChipAvatar", classNames?.avatar)}>
          {avatar}
        </span>
      ) : null}
      {startContent}
      {children !== undefined && children !== null ? (
        <span className={mergeClassName("oksChipContent", classNames?.content)}>
          {children}
        </span>
      ) : null}
      {closeButton ?? endContent}
    </div>
  );

  return chipElement;
});

Chip.displayName = "Chip";
