import type { CSSProperties, InputHTMLAttributes, ReactNode } from "react";
import { forwardRef, useEffect, useId, useMemo, useState } from "react";
import type {
  FormElementLabelPlacement,
  FormElementSize,
  FormElementTone,
  FormElementVariant,
} from "../types";
import { getToneVar, mergeClassName } from "../internal";
import type { SelectOption } from "../SelectField/SelectField";
import { SelectField } from "../SelectField/SelectField";
import "./PhoneField.module.css";

export type PhoneValue = { code: string; phone: string };

export type PhoneCountryOption = {
  code: string;
  name?: string;
  label?: string;
  flag?: ReactNode;
  shortCode?: string;
  key?: string;
};

export type PhoneFieldProps = Omit<
  InputHTMLAttributes<HTMLInputElement>,
  "type" | "size" | "color" | "value" | "defaultValue" | "onChange"
> & {
  label?: ReactNode;
  labelPlacement?: FormElementLabelPlacement;
  description?: ReactNode;
  error?: ReactNode | boolean;
  size?: FormElementSize;
  variant?: FormElementVariant;
  tone?: FormElementTone;
  colorDepth?: number;
  value?: PhoneValue;
  defaultValue?: PhoneValue;
  defaultCountryCode?: string;
  countryCodeMode?: "select" | "hidden";
  countryOptions?: PhoneCountryOption[];
  numbersOnly?: boolean;
  onChange?: (next: PhoneValue) => void;
  phonePlaceholder?: string;
  style?: CSSProperties;
};

const defaultCountries: PhoneCountryOption[] = [
  { name: "United States", code: "+1", flag: "🇺🇸", shortCode: "US" },
  { name: "India", code: "+91", flag: "🇮🇳", shortCode: "IN" },
  { name: "United Kingdom", code: "+44", flag: "🇬🇧", shortCode: "GB" },
  { name: "United Arab Emirates", code: "+971", flag: "🇦🇪", shortCode: "AE" },
];

const normalizePhoneValue = (v: unknown, fallbackCode: string): PhoneValue => {
  if (v && typeof v === "object") {
    const obj = v as any;
    return { code: String(obj.code || fallbackCode), phone: String(obj.phone ?? "") };
  }
  return { code: fallbackCode, phone: "" };
};

export const PhoneField = forwardRef<HTMLInputElement, PhoneFieldProps>(
  (props, ref) => {
    const {
      label,
      labelPlacement = "top",
      description,
      error,
      size = "md",
      variant = "outline",
      tone = "primary",
      colorDepth = 500,
      className,
      id,
      name,
      required,
      disabled,
      value,
      defaultValue,
      defaultCountryCode,
      countryCodeMode = "select",
      countryOptions,
      numbersOnly = true,
      onChange,
      phonePlaceholder = "Phone number",
      style,
      onBlur,
      ...rest
    } = props;

    const reactId = useId();
    const baseId = id ?? `oks-phone-${reactId}`;

    const describedBy = (rest as any)["aria-describedby"];
    const descriptionId = description ? `${baseId}-description` : undefined;
    const errorId = error && error !== true ? `${baseId}-error-message` : undefined;
    const ariaDescribedBy = [describedBy, descriptionId, errorId].filter(Boolean).join(" ");

    const isInvalid = Boolean(error);

    const toneVars: CSSProperties = {
      "--oks-phone-tone": getToneVar(tone, colorDepth),
    } as unknown as CSSProperties;

    const resolvedCountries = countryOptions && countryOptions.length > 0 ? countryOptions : defaultCountries;
    const fallbackCode = defaultCountryCode ?? resolvedCountries[0]?.code ?? "";

    const [uncontrolled, setUncontrolled] = useState<PhoneValue>(() =>
      normalizePhoneValue(value ?? defaultValue, fallbackCode),
    );

    useEffect(() => {
      if (value !== undefined) setUncontrolled(normalizePhoneValue(value, fallbackCode));
    }, [value, fallbackCode]);

    const currentValue = value !== undefined ? normalizePhoneValue(value, fallbackCode) : uncontrolled;

    const getCountryName = (c: PhoneCountryOption) => {
      if (c.name) return String(c.name);
      if (c.label) {
        const s = String(c.label);
        const m = s.match(/^\s*(.*?)\s*\(/);
        if (m?.[1]) return m[1].trim();
        return s.trim();
      }
      return "";
    };

    const getCountryShort = (c: PhoneCountryOption) => {
      if (c.shortCode) return String(c.shortCode);
      if (c.label) {
        const s = String(c.label);
        const m = s.match(/^\s*([A-Za-z]{2,3})\s*\(/);
        if (m?.[1]) return m[1].trim();
      }
      return "";
    };

    const codeOptions = useMemo<SelectOption[]>(
      () =>
        resolvedCountries.map((c) => ({
          label: (
            <span className="oksPhoneCountryOption">
              {c.flag ? (
                <span className="oksPhoneCountryFlag">{c.flag}</span>
              ) : getCountryShort(c) ? (
                <span className="oksPhoneCountryShort">{getCountryShort(c)}</span>
              ) : null}
              {getCountryName(c) ? (
                <span className="oksPhoneCountryName">{getCountryName(c)}</span>
              ) : null}
              <span className="oksPhoneCountryCode">{c.code}</span>
            </span>
          ),
          value: c.code,
          key: c.key ?? c.code,
        })),
      [resolvedCountries],
    );

    const resolvedPhonePlaceholder = useMemo(() => {
      if (labelPlacement !== "floating") return phonePlaceholder;
      if (!label) return phonePlaceholder;
      if (phonePlaceholder !== undefined) return phonePlaceholder;
      return " ";
    }, [labelPlacement, label, phonePlaceholder]);

    const topLabel = labelPlacement === "top" ? label : null;
    const floatingLabel = labelPlacement === "floating" ? label : null;

    const emit = (next: PhoneValue) => {
      if (value === undefined) setUncontrolled(next);
      onChange?.(next);
    };

    const inputMode =
      numbersOnly && rest.inputMode === undefined ? "numeric" : rest.inputMode;
    const htmlPattern =
      numbersOnly && rest.pattern === undefined ? "\\d*" : rest.pattern;

    return (
      <div
        className={mergeClassName("oksPhoneField", className)}
        data-size={size}
        data-variant={variant}
        data-tone={tone}
        data-country-code-mode={countryCodeMode}
        data-label-placement={labelPlacement}
        data-invalid={isInvalid ? "true" : "false"}
        data-disabled={disabled ? "true" : "false"}
        style={{ ...toneVars, ...style }}
      >
        {topLabel ? (
          <label className="oksPhoneFieldLabel" htmlFor={`${baseId}-phone`}>
            {topLabel}
            {required ? <span aria-hidden="true">*</span> : null}
          </label>
        ) : null}

        <div className="oksPhoneFieldControl">
          {countryCodeMode === "select" ? (
            <div className="oksPhoneFieldCode">
              <SelectField
                aria-label="Country code"
                size={size}
                variant={variant}
                tone={tone}
                colorDepth={colorDepth}
                options={codeOptions}
                value={String(currentValue.code ?? "")}
                disabled={disabled}
                onChange={(e: any) =>
                  emit({
                    code: String(e?.target?.value ?? ""),
                    phone: currentValue.phone,
                  })
                }
                onBlur={onBlur as any}
              />
              <span className="oksPhoneDialCode" aria-hidden="true">
                {String(currentValue.code ?? "")}
              </span>
            </div>
          ) : null}

          <div className="oksPhoneFieldInputWrap">
            <input
              {...rest}
              ref={ref}
              id={`${baseId}-phone`}
              name={name}
              type="tel"
              disabled={disabled}
              required={required}
              className="oksPhoneFieldInput"
              placeholder={resolvedPhonePlaceholder}
              aria-invalid={isInvalid ? "true" : undefined}
              aria-describedby={ariaDescribedBy || undefined}
              aria-errormessage={errorId}
              value={String(currentValue.phone ?? "")}
              inputMode={inputMode}
              pattern={htmlPattern}
              onChange={(e) => {
                const raw = e.currentTarget.value;
                const nextPhone = numbersOnly ? raw.replace(/[^\d]/g, "") : raw;
                const max = rest.maxLength;
                const capped =
                  typeof max === "number" && Number.isFinite(max) && max >= 0
                    ? nextPhone.slice(0, max)
                    : nextPhone;
                emit({ code: currentValue.code, phone: capped });
              }}
              onBlur={onBlur as any}
            />

            {floatingLabel ? (
              <label className="oksPhoneFieldLabel" htmlFor={`${baseId}-phone`}>
                {floatingLabel}
                {required ? <span aria-hidden="true">*</span> : null}
              </label>
            ) : null}
          </div>
        </div>

        {description ? (
          <div id={descriptionId} className="oksPhoneFieldDescription">
            {description}
          </div>
        ) : null}

        {error && error !== true ? (
          <div id={errorId} className="oksPhoneFieldError" role="alert">
            {error}
          </div>
        ) : null}
      </div>
    );
  },
);

PhoneField.displayName = "PhoneField";
