import type { CSSProperties, ReactElement, ReactNode } from "react";
import {
  cloneElement,
  isValidElement,
  useEffect,
  useId,
  useMemo,
  useRef,
  useState,
} from "react";
import { useReducedMotion } from "../../motion";
import { Portal } from "../../primitives";
import { clamp, composeEventHandlers, composeRefs } from "../../utils";
import {
  computeTooltipPosition,
  type TooltipAlign,
  type TooltipSide,
} from "./tooltipPositioning";
import "./Tooltip.module.css";

export type TooltipSize = "sm" | "md" | "lg";
export type TooltipColor =
  | "default"
  | "primary"
  | "secondary"
  | "info"
  | "success"
  | "warning"
  | "danger";
export type TooltipRadius = "none" | "sm" | "md" | "lg" | "full";
export type TooltipShadow = "none" | "sm" | "md" | "lg";

export type TooltipColorDepth =
  | 50
  | 100
  | 200
  | 300
  | 400
  | 500
  | 600
  | 700
  | 800
  | 900
  | 950;

export type TooltipPlacement =
  | "top"
  | "top-start"
  | "top-end"
  | "bottom"
  | "bottom-start"
  | "bottom-end"
  | "left"
  | "left-start"
  | "left-end"
  | "right"
  | "right-start"
  | "right-end";

export type TooltipClassNames = Partial<
  Record<"base" | "content" | "arrow", string>
>;

export type TooltipProps = {
  children: ReactNode;
  content: ReactNode;
  size?: TooltipSize;
  color?: TooltipColor;
  colorDepth?: TooltipColorDepth;
  radius?: TooltipRadius;
  shadow?: TooltipShadow;
  placement?: TooltipPlacement;
  delay?: number;
  closeDelay?: number;
  isOpen?: boolean;
  defaultOpen?: boolean;
  onOpenChange?: (isOpen: boolean) => void;
  onClose?: () => void;
  offset?: number;
  containerPadding?: number;
  crossOffset?: number;
  showArrow?: boolean;
  shouldFlip?: boolean;
  triggerScaleOnOpen?: boolean;
  isKeyboardDismissDisabled?: boolean;
  isDismissable?: boolean;
  shouldCloseOnBlur?: boolean;
  motionProps?: unknown;
  portalContainer?: Element | DocumentFragment | null;
  updatePositionDeps?: any[];
  isDisabled?: boolean;
  disableAnimation?: boolean;
  className?: string;
  classNames?: TooltipClassNames;
  shouldCloseOnInteractOutside?: (element: HTMLElement) => boolean;
};

function mergeClassName(a: unknown, b: unknown) {
  const sa = typeof a === "string" ? a : "";
  const sb = typeof b === "string" ? b : "";
  return [sa, sb].filter(Boolean).join(" ");
}

const ALLOWED_DEPTHS = [
  50, 100, 200, 300, 400, 500, 600, 700, 800, 900, 950,
] as const;

function snapDepth(input: number) {
  const clamped = clamp(input, 50, 950);
  const first: number = ALLOWED_DEPTHS[0] ?? 100;
  let best: number = first;
  let bestDiff = Math.abs(best - clamped);
  for (const d of ALLOWED_DEPTHS) {
    const diff = Math.abs(d - clamped);
    if (diff < bestDiff) {
      best = d;
      bestDiff = diff;
    }
  }
  return best;
}

function getColorVar(color: string, depth: number) {
  const fallback = `var(--oks-color-default-${depth}, var(--oks-color-primary-${depth}, #3b82f6))`;
  if (color === "default") return fallback;
  return `var(--oks-color-${color}-${depth}, ${fallback})`;
}

export function TooltipDefaultIcon() {
  return (
    <svg
      width="20"
      height="20"
      viewBox="0 0 14 14"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      aria-hidden="true"
      focusable="false"
    >
      <path
        d="M7 12.25C4.1005 12.25 1.75 9.8995 1.75 7C1.75 4.1005 4.1005 1.75 7 1.75C9.8995 1.75 12.25 4.1005 12.25 7C12.25 9.8995 9.8995 12.25 7 12.25Z"
        stroke="currentColor"
        strokeWidth="1.2"
      />
      <path
        d="M7 6.125V10"
        stroke="currentColor"
        strokeWidth="1.2"
        strokeLinecap="round"
      />
      <path
        d="M7 4.375H7.005"
        stroke="currentColor"
        strokeWidth="1.8"
        strokeLinecap="round"
      />
    </svg>
  );
}

export function Tooltip(props: TooltipProps) {
  const {
    children,
    content,
    size = "md",
    color = "default",
    colorDepth = 100,
    radius = "md",
    shadow = "sm",
    placement = "top",
    delay = 0,
    closeDelay = 500,
    isOpen,
    defaultOpen = false,
    onOpenChange,
    onClose,
    offset = 7,
    containerPadding = 12,
    crossOffset = 0,
    showArrow = false,
    shouldFlip = true,
    triggerScaleOnOpen = false,
    isKeyboardDismissDisabled = false,
    isDismissable = false,
    shouldCloseOnBlur = true,
    portalContainer,
    updatePositionDeps,
    isDisabled = false,
    disableAnimation = false,
    className,
    classNames,
    shouldCloseOnInteractOutside,
  } = props;

  const reactId = useId();
  const tooltipId = `oks-tooltip-${reactId.replace(/[:]/g, "")}`;

  const isControlled = isOpen !== undefined;
  const [uncontrolledOpen, setUncontrolledOpen] = useState(defaultOpen);
  const actualOpen = !isDisabled && (isControlled ? isOpen : uncontrolledOpen);

  const [mounted, setMounted] = useState(false);
  const reducedMotion = useReducedMotion();

  const triggerRef = useRef<HTMLElement | null>(null);
  const contentRef = useRef<HTMLDivElement | null>(null);
  const openTimerRef = useRef<number | null>(null);
  const closeTimerRef = useRef<number | null>(null);
  const [position, setPosition] = useState<{
    top: number;
    left: number;
    placedSide: TooltipSide;
    arrowX?: number;
    arrowY?: number;
  } | null>(null);

  const setOpen = (next: boolean) => {
    onOpenChange?.(next);
    if (!isControlled) setUncontrolledOpen(next);
    if (!next) onClose?.();
  };

  const clearOpenTimer = () => {
    if (openTimerRef.current !== null) {
      window.clearTimeout(openTimerRef.current);
      openTimerRef.current = null;
    }
  };

  const clearCloseTimer = () => {
    if (closeTimerRef.current !== null) {
      window.clearTimeout(closeTimerRef.current);
      closeTimerRef.current = null;
    }
  };

  const scheduleOpen = (e?: any) => {
    if (isDisabled) return;
    const currentTarget = e?.currentTarget;
    if (currentTarget instanceof HTMLElement) {
      triggerRef.current = currentTarget;
    }
    clearCloseTimer();
    clearOpenTimer();
    updatePosition();
    openTimerRef.current = window.setTimeout(() => setOpen(true), delay);
  };

  const scheduleClose = () => {
    clearOpenTimer();
    clearCloseTimer();
    closeTimerRef.current = window.setTimeout(() => setOpen(false), closeDelay);
  };

  const closeNow = () => {
    clearOpenTimer();
    clearCloseTimer();
    setOpen(false);
  };

  const { side, align } = useMemo(() => {
    const [rawSide, rawAlign] = placement.split("-") as [
      TooltipSide | undefined,
      TooltipAlign | undefined,
    ];
    const parsedSide: TooltipSide =
      rawSide === "top" ||
      rawSide === "bottom" ||
      rawSide === "left" ||
      rawSide === "right"
        ? rawSide
        : "top";
    const parsedAlign: TooltipAlign =
      rawAlign === "start" || rawAlign === "end" ? rawAlign : "center";
    return { side: parsedSide, align: parsedAlign };
  }, [placement]);

  const updatePosition = () => {
    const triggerEl = triggerRef.current;
    const contentEl = contentRef.current;
    if (!triggerEl || !contentEl) return;
    const triggerRect = triggerEl.getBoundingClientRect();
    const tooltipRect = contentEl.getBoundingClientRect();

    const arrowEl = showArrow
      ? (contentEl.querySelector(".oksTooltipArrow") as HTMLElement | null)
      : null;
    const contentWrapperEl = contentEl.querySelector(
      ".oksTooltipContent",
    ) as HTMLElement | null;

    const parsedArrowSize = arrowEl
      ? Number.parseFloat(window.getComputedStyle(arrowEl).width)
      : Number.NaN;
    const arrowSize =
      Number.isFinite(parsedArrowSize) && parsedArrowSize > 0
        ? parsedArrowSize
        : 10;

    const parsedPaddingX = contentWrapperEl
      ? Number.parseFloat(window.getComputedStyle(contentWrapperEl).paddingLeft)
      : Number.NaN;
    const arrowPaddingX =
      Number.isFinite(parsedPaddingX) && parsedPaddingX > 0
        ? parsedPaddingX
        : 12;

    const parsedPaddingY = contentWrapperEl
      ? Number.parseFloat(window.getComputedStyle(contentWrapperEl).paddingTop)
      : Number.NaN;
    const arrowPaddingY =
      Number.isFinite(parsedPaddingY) && parsedPaddingY > 0
        ? parsedPaddingY
        : 8;

    const arrowCornerInset =
      radius === "full"
        ? Math.min(tooltipRect.width, tooltipRect.height) / 2
        : 0;

    setPosition(
      computeTooltipPosition({
        triggerRect,
        tooltipRect,
        side,
        align,
        offset,
        collisionPadding: containerPadding,
        crossOffset,
        shouldFlip,
        arrowSize,
        arrowPaddingX,
        arrowPaddingY,
        arrowCornerInset,
        strategy: "fixed",
      }),
    );
  };

  useEffect(() => {
    setMounted(true);
    return () => {
      if (typeof window === "undefined") return;
      clearOpenTimer();
      clearCloseTimer();
    };
  }, []);

  useEffect(() => {
    if (!mounted) return;
    if (!actualOpen) return;
    updatePosition();

    if (typeof window === "undefined") return;
    const rafId = window.requestAnimationFrame(() => updatePosition());
    const onScrollOrResize = () => updatePosition();
    window.addEventListener("scroll", onScrollOrResize, true);
    window.addEventListener("resize", onScrollOrResize);

    let ro: ResizeObserver | null = null;
    if (typeof ResizeObserver !== "undefined") {
      ro = new ResizeObserver(onScrollOrResize);
      if (triggerRef.current) ro.observe(triggerRef.current);
      if (contentRef.current) ro.observe(contentRef.current);
    }

    return () => {
      window.cancelAnimationFrame(rafId);
      window.removeEventListener("scroll", onScrollOrResize, true);
      window.removeEventListener("resize", onScrollOrResize);
      ro?.disconnect();
    };
  }, [
    mounted,
    actualOpen,
    side,
    align,
    offset,
    containerPadding,
    crossOffset,
    shouldFlip,
    updatePositionDeps,
  ]);

  useEffect(() => {
    if (!mounted) return;
    if (!actualOpen) return;
    if (typeof document === "undefined") return;
    const onKeyDown = (e: KeyboardEvent) => {
      if (isKeyboardDismissDisabled) return;
      if (e.key === "Escape") closeNow();
    };
    document.addEventListener("keydown", onKeyDown);
    return () => document.removeEventListener("keydown", onKeyDown);
  }, [mounted, actualOpen, isKeyboardDismissDisabled]);

  useEffect(() => {
    if (!mounted) return;
    if (!actualOpen) return;
    if (!isDismissable) return;
    if (typeof document === "undefined") return;

    const onPointerDown = (e: PointerEvent) => {
      const target = e.target;
      if (!(target instanceof Node)) return;
      if (triggerRef.current?.contains(target)) return;
      if (contentRef.current?.contains(target)) return;

      const element = target instanceof HTMLElement ? target : null;
      if (element && shouldCloseOnInteractOutside) {
        const shouldClose = shouldCloseOnInteractOutside(element);
        if (!shouldClose) return;
      }
      closeNow();
    };

    document.addEventListener("pointerdown", onPointerDown, true);
    return () =>
      document.removeEventListener("pointerdown", onPointerDown, true);
  }, [mounted, actualOpen, isDismissable, shouldCloseOnInteractOutside]);

  const getTriggerProps = (existingProps?: any) => ({
    "aria-describedby": actualOpen ? tooltipId : undefined,
    onPointerEnter: composeEventHandlers(
      existingProps?.onPointerEnter,
      (e: any) => scheduleOpen(e),
    ),
    onPointerLeave: composeEventHandlers(existingProps?.onPointerLeave, () =>
      scheduleClose(),
    ),
    onFocus: composeEventHandlers(existingProps?.onFocus, (e: any) =>
      scheduleOpen(e),
    ),
    onBlur: composeEventHandlers(existingProps?.onBlur, () => {
      if (!shouldCloseOnBlur) return;
      scheduleClose();
    }),
    onKeyDown: composeEventHandlers(existingProps?.onKeyDown, (e: any) => {
      if (isKeyboardDismissDisabled) return;
      if (e?.key === "Escape") closeNow();
    }),
  });

  const isPositionPending = actualOpen && position === null;
  const contentStyle: CSSProperties = {
    position: "fixed",
    top: position?.top ?? 0,
    left: position?.left ?? 0,
    visibility: isPositionPending ? "hidden" : undefined,
    ...(position?.arrowX !== undefined
      ? ({ ["--oks-tooltip-arrow-x" as any]: `${position.arrowX}px` } as any)
      : null),
    ...(position?.arrowY !== undefined
      ? ({ ["--oks-tooltip-arrow-y" as any]: `${position.arrowY}px` } as any)
      : null),
  };

  const resolvedDepth =
    typeof colorDepth === "number" ? snapDepth(colorDepth) : 100;
  const resolvedFg = resolvedDepth <= 400 ? "#000" : "#fff";
  const tooltipVars: CSSProperties = {
    ["--oks-tooltip-bg" as any]: getColorVar(color, resolvedDepth),
    ["--oks-tooltip-fg" as any]: resolvedFg,
  } as unknown as CSSProperties;

  const triggerNode = isValidElement(children) ? (
    (() => {
      const child = children as ReactElement;
      const triggerRefProp = (child as unknown as { ref?: unknown }).ref as
        | ((node: HTMLElement | null) => void)
        | { current: HTMLElement | null }
        | null
        | undefined;

      return cloneElement(child, {
        ref: composeRefs(triggerRefProp as any, (node: HTMLElement | null) => {
          triggerRef.current = node;
        }),
        ...getTriggerProps(child.props),
      });
    })()
  ) : (
    <span
      ref={(node) => {
        triggerRef.current = node;
      }}
      {...getTriggerProps()}
    >
      {children}
    </span>
  );

  const motionState =
    disableAnimation || reducedMotion
      ? "reduced"
      : actualOpen
        ? "open"
        : "closed";

  const actualPlacement = useMemo(() => {
    const placedSide = position?.placedSide ?? side;
    const suffix = align === "center" ? "" : `-${align}`;
    return `${placedSide}${suffix}` as TooltipPlacement;
  }, [position?.placedSide, side, align]);

  const tooltipNode =
    mounted && !isDisabled ? (
      <div
        ref={(node) => {
          contentRef.current = node;
        }}
        id={tooltipId}
        role="tooltip"
        aria-hidden={!actualOpen}
        data-open={actualOpen ? "true" : "false"}
        data-placement={actualPlacement}
        data-disabled={isDisabled ? "true" : "false"}
        data-size={size}
        data-color={color}
        data-radius={radius}
        data-shadow={shadow}
        data-motion={motionState}
        className={mergeClassName(
          mergeClassName("oksTooltipBase", classNames?.base),
          className,
        )}
        style={{ ...tooltipVars, ...contentStyle }}
      >
        {showArrow ? (
          <span
            className={mergeClassName("oksTooltipArrow", classNames?.arrow)}
          />
        ) : null}
        <div
          className={mergeClassName("oksTooltipContent", classNames?.content)}
        >
          {content}
        </div>
      </div>
    ) : null;

  return (
    <>
      <span
        className="oksTooltipTrigger"
        data-open={actualOpen ? "true" : "false"}
        data-trigger-scale={triggerScaleOnOpen ? "true" : "false"}
        data-motion={disableAnimation || reducedMotion ? "reduced" : "default"}
      >
        {triggerNode}
      </span>
      <Portal container={portalContainer}>{tooltipNode}</Portal>
    </>
  );
}

export default Tooltip;
