import type { ReactNode } from "react";
import React, { useEffect, useId, useMemo, useRef, useState } from "react";
import { CheckboxGroupField } from "./CustomFormElements/CheckboxGroupField/CheckboxGroupField";
import { DatePickerField } from "./CustomFormElements/DatePickerField/DatePickerField";
import { PasswordField } from "./CustomFormElements/PasswordField/PasswordField";
import { PhoneField } from "./CustomFormElements/PhoneField/PhoneField";
import { RadioGroupField } from "./CustomFormElements/RadioGroupField/RadioGroupField";
import { SelectField } from "./CustomFormElements/SelectField/SelectField";
import { SwitchField } from "./CustomFormElements/SwitchField/SwitchField";
import { TextAreaField } from "./CustomFormElements/TextAreaField/TextAreaField";
import { TextField } from "./CustomFormElements/TextField/TextField";
import type { FormData, FormErrors } from "./FormWrapper";
import { useOptionalFormContext } from "./FormWrapper";
import type { FieldValidation } from "./Validation";
import { getFirstError, validateField } from "./Validation";

export type FormFieldType =
  | "text"
  | "password"
  | "email"
  | "file"
  | "phone"
  | "select"
  | "radio"
  | "checkbox"
  | "switch"
  | "datepicker"
  | "textarea";

type CommonProps = {
  label?: ReactNode;
  description?: ReactNode;
  labelPlacement?: "top" | "floating";
  size?: "xs" | "xs-sm" | "sm" | "md" | "lg" | "xl";
  variant?: "outline" | "soft" | "underline";
  color?:
    | "default"
    | "primary"
    | "info"
    | "success"
    | "warning"
    | "danger"
    | "secondary"
    | (string & {});
  tone?:
    | "default"
    | "primary"
    | "info"
    | "success"
    | "warning"
    | "danger"
    | "secondary"
    | (string & {});
  colorDepth?: number;
  name?: string;
  id?: string;
  validation?: FieldValidation;
  error?: ReactNode;
  touched?: boolean;
};

export type FormFieldSetProps =
  | (CommonProps &
      Omit<React.ComponentProps<typeof TextField>, "error" | "id" | "name"> & {
        type?: "text" | "password" | "email" | "file";
      })
  | (CommonProps &
      Omit<
        React.ComponentProps<typeof TextAreaField>,
        "error" | "id" | "name"
      > & {
        type: "textarea";
      })
  | (CommonProps &
      Omit<
        React.ComponentProps<typeof SelectField>,
        "error" | "id" | "name"
      > & {
        type: "select";
        placeholder?: ReactNode;
      })
  | (CommonProps &
      Omit<
        React.ComponentProps<typeof RadioGroupField>,
        "error" | "id" | "name"
      > & {
        type: "radio";
      })
  | (CommonProps &
      Omit<
        React.ComponentProps<typeof CheckboxGroupField>,
        "error" | "id" | "name"
      > & {
        type: "checkbox";
      })
  | (CommonProps &
      Omit<
        React.ComponentProps<typeof SwitchField>,
        "error" | "id" | "name"
      > & {
        type: "switch";
      })
  | (CommonProps &
      Omit<
        React.ComponentProps<typeof DatePickerField>,
        "error" | "id" | "name"
      > & {
        type: "datepicker";
      })
  | (CommonProps &
      Omit<
        React.ComponentProps<typeof PhoneField>,
        "error" | "id" | "name"
      > & {
        type: "phone";
      });

const sanitize = (str: unknown) =>
  String(str || "")
    .toLowerCase()
    .replace(/\s+/g, "_")
    .replace(/[^a-z0-9_]/g, "");

function getContextValue(formData: FormData, name: string) {
  if (!formData) return undefined;
  return (formData as any)[name];
}

function getContextError(errors: FormErrors, name: string) {
  if (!errors) return undefined;
  return (errors as any)[name];
}

export const FormFieldSet = (props: FormFieldSetProps) => {
  const {
    type = "text",
    label,
    description,
    labelPlacement,
    size = "md",
    variant = "outline",
    color,
    tone,
    colorDepth = 500,
    name,
    id,
    validation,
    error,
    touched,
    ...rest
  } = props as any;

  const resolvedColor = color ?? tone ?? "default";

  const {
    onChange: onChangeProp,
    onBlur: onBlurProp,
    value: valueProp,
    defaultValue: defaultValueProp,
    ...restPropsRaw
  } = rest as any;

  const formContext = useOptionalFormContext();
  const disableAutofill = Boolean((formContext as any)?.disableAutofill);
  const { autoComplete: autoCompleteProp, ...restPropsBase } =
    (restPropsRaw as any) ?? {};
  const resolvedAutoComplete =
    autoCompleteProp ??
    (disableAutofill ? (type === "password" ? "new-password" : "off") : undefined);
  const restProps =
    resolvedAutoComplete === undefined
      ? (restPropsBase as any)
      : ({ ...(restPropsBase as any), autoComplete: resolvedAutoComplete } as any);
  const reactId = useId();

  const sanitizedReactId = useMemo(
    () => String(reactId).replace(/[^a-z0-9_-]/gi, ""),
    [reactId],
  );

  const placeholderCandidate = (restProps as any)?.placeholder;

  const baseName = useMemo(() => {
    if (id) return sanitize(id);
    if (label) return sanitize(label);
    if (placeholderCandidate) return sanitize(placeholderCandidate);
    return "field";
  }, [id, label, placeholderCandidate]);

  const nameRef = useRef<string | null>(null);
  if (nameRef.current === null) {
    if (name) {
      nameRef.current = name;
    } else if (typeof formContext?.getUniqueFieldName === "function") {
      nameRef.current = formContext.getUniqueFieldName(baseName);
    } else {
      nameRef.current = baseName;
    }
  }

  const idRef = useRef<string | null>(null);
  if (idRef.current === null) {
    if (id) {
      idRef.current = id;
    } else {
      const suffix = sanitizedReactId || "id";
      idRef.current = `${baseName}_${suffix}`;
    }
  }

  const fieldName = nameRef.current ?? baseName;
  const fieldId = idRef.current ?? `${baseName}_${sanitizedReactId || "id"}`;

  const normalizedValidation = useMemo(() => {
    if (
      validation &&
      validation.rules &&
      Object.keys(validation.rules).length > 0
    )
      return validation;
    return null;
  }, [validation]);

  const registerFieldFn = formContext?.registerField;
  const unregisterFieldFn = formContext?.unregisterField;

  const isRegisteredRef = useRef(false);
  useEffect(() => {
    if (registerFieldFn && normalizedValidation && !isRegisteredRef.current) {
      registerFieldFn(fieldName, normalizedValidation);
      isRegisteredRef.current = true;
    }
    return () => {
      if (unregisterFieldFn && isRegisteredRef.current) {
        unregisterFieldFn(fieldName);
        isRegisteredRef.current = false;
      }
    };
  }, [fieldName, normalizedValidation, registerFieldFn, unregisterFieldFn]);

  useEffect(() => {
    if (registerFieldFn && normalizedValidation && isRegisteredRef.current) {
      registerFieldFn(fieldName, normalizedValidation);
    }
  }, [normalizedValidation, fieldName, registerFieldFn]);

  const [localValue, setLocalValue] = useState<unknown>(() => {
    if (valueProp !== undefined) return valueProp;
    if (defaultValueProp !== undefined) return defaultValueProp;
    if (type === "checkbox") return [];
    if (type === "switch") return false;
    if (type === "file") return null;
    return "";
  });
  const [localTouched, setLocalTouched] = useState(false);
  const [localError, setLocalError] = useState<string | null>(null);

  useEffect(() => {
    if (!formContext && normalizedValidation?.rules) {
      const errors = validateField(
        localValue,
        normalizedValidation.rules,
        normalizedValidation.message ?? {},
      );
      setLocalError(getFirstError(errors));
    }
  }, [formContext, localValue, normalizedValidation]);

  const currentValue = (() => {
    if (formContext) {
      const v = getContextValue(formContext.formData, fieldName);
      if (v !== undefined) return v;
    }
    if (valueProp !== undefined) return valueProp;
    return localValue;
  })();

  const fieldTouched =
    touched !== undefined
      ? touched
      : formContext
        ? Boolean((formContext.touched as any)[fieldName])
        : localTouched;

  const fieldError =
    error !== undefined
      ? error
      : formContext
        ? getContextError(formContext.errors, fieldName)
        : localError;

  const shouldShowError = Boolean(fieldError) && Boolean(fieldTouched);

  const handleValueChange = (next: unknown) => {
    const nextValue = (() => {
      if (next && typeof next === "object" && "target" in (next as any)) {
        const target = (next as any).target as any;
        if (type === "file") return target.files ?? null;
        return target.value;
      }
      return next;
    })();

    if (formContext) {
      formContext.handleFieldChange(fieldName, nextValue);
      if (
        formContext.validationMode === "change" &&
        normalizedValidation?.rules
      ) {
        formContext.validateFieldValue(
          fieldName,
          nextValue,
          normalizedValidation,
        );
      }
    } else {
      setLocalValue(nextValue);
      if (normalizedValidation?.rules) {
        const errors = validateField(
          nextValue,
          normalizedValidation.rules,
          normalizedValidation.message ?? {},
        );
        setLocalError(getFirstError(errors));
      }
    }
    onChangeProp?.(next);
  };

  const handleBlur = (event: unknown) => {
    if (formContext) {
      formContext.handleFieldBlur(fieldName);
    } else {
      setLocalTouched(true);
      if (normalizedValidation?.rules) {
        const errors = validateField(
          localValue,
          normalizedValidation.rules,
          normalizedValidation.message ?? {},
        );
        setLocalError(getFirstError(errors));
      }
    }
    onBlurProp?.(event);
  };

  const shared = {
    label,
    description,
    labelPlacement,
    size,
    variant,
    color: resolvedColor,
    colorDepth,
    id: fieldId,
    name: fieldName,
    disabled: (restProps as any).disabled,
    required: (restProps as any).required,
  };

  if (type === "textarea") {
    const textValue = currentValue == null ? "" : String(currentValue);
    return (
      <TextAreaField
        {...(restProps as any)}
        {...shared}
        value={textValue as any}
        onChange={handleValueChange as any}
        onBlur={handleBlur as any}
        error={shouldShowError ? (fieldError as any) : false}
      />
    );
  }

  if (type === "select") {
    const { placeholder, placeholderOption, ...selectRest } = restProps as any;
    const multiple = Boolean((restProps as any).multiple);
    const selectValue = multiple
      ? Array.isArray(currentValue)
        ? (currentValue as any[]).map((v) => String(v))
        : []
      : currentValue == null
        ? ""
        : String(currentValue);
    return (
      <SelectField
        {...(selectRest as any)}
        {...shared}
        placeholderOption={placeholderOption ?? placeholder}
        value={selectValue as any}
        onChange={handleValueChange as any}
        onBlur={handleBlur as any}
        error={shouldShowError ? (fieldError as any) : false}
      />
    );
  }

  if (type === "radio") {
    const radioValue = currentValue == null ? "" : String(currentValue);
    return (
      <RadioGroupField
        {...(restProps as any)}
        {...shared}
        value={radioValue as any}
        onChange={(v: string) => handleValueChange(v)}
        error={shouldShowError ? (fieldError as any) : false}
      />
    );
  }

  if (type === "checkbox") {
    const checkboxValue = Array.isArray(currentValue)
      ? (currentValue as any[]).map((v) => String(v))
      : [];
    return (
      <CheckboxGroupField
        {...(restProps as any)}
        {...shared}
        value={checkboxValue as any}
        onChange={(v: string[]) => handleValueChange(v)}
        error={shouldShowError ? (fieldError as any) : false}
      />
    );
  }

  if (type === "switch") {
    return (
      <SwitchField
        {...(restProps as any)}
        {...shared}
        checked={Boolean(currentValue)}
        onChange={(v: boolean) => handleValueChange(v)}
        error={shouldShowError ? (fieldError as any) : false}
      />
    );
  }

  if (type === "datepicker") {
    const isRange = Boolean((restProps as any).range);
    const datepickerValue = isRange
      ? currentValue && typeof currentValue === "object"
        ? {
            start: String((currentValue as any).start ?? ""),
            end: String((currentValue as any).end ?? ""),
          }
        : { start: "", end: "" }
      : currentValue == null
        ? ""
        : String(currentValue);
    return (
      <DatePickerField
        {...(restProps as any)}
        {...shared}
        value={datepickerValue as any}
        onChange={(v: any) => handleValueChange(v)}
        onBlur={handleBlur as any}
        error={shouldShowError ? (fieldError as any) : false}
      />
    );
  }

  if (type === "phone") {
    const defaultCountryCode = (restProps as any).defaultCountryCode;
    const fallbackCode = String(defaultCountryCode ?? "+1");
    const phoneValue =
      currentValue && typeof currentValue === "object"
        ? {
            code: String((currentValue as any).code || fallbackCode),
            phone: String((currentValue as any).phone ?? ""),
          }
        : { code: fallbackCode, phone: "" };
    return (
      <PhoneField
        {...(restProps as any)}
        {...shared}
        value={phoneValue as any}
        onChange={(v: any) => handleValueChange(v)}
        onBlur={handleBlur as any}
        error={shouldShowError ? (fieldError as any) : false}
      />
    );
  }

  if (type === "password") {
    const passwordValue = currentValue == null ? "" : String(currentValue);
    const strongPassword = (normalizedValidation?.rules as any)?.strongPassword;
    return (
      <PasswordField
        {...(restProps as any)}
        {...shared}
        value={passwordValue as any}
        onChange={handleValueChange as any}
        onBlur={handleBlur as any}
        error={shouldShowError ? (fieldError as any) : false}
        strongPassword={strongPassword}
      />
    );
  }

  if (type === "file") {
    return (
      <TextField
        {...(restProps as any)}
        {...shared}
        type="file"
        onChange={handleValueChange as any}
        onBlur={handleBlur as any}
        error={shouldShowError ? (fieldError as any) : false}
      />
    );
  }

  const inputValue = currentValue == null ? "" : String(currentValue);
  return (
    <TextField
      {...(restProps as any)}
      {...shared}
      type={type}
      value={inputValue as any}
      onChange={handleValueChange as any}
      onBlur={handleBlur as any}
      error={shouldShowError ? (fieldError as any) : false}
    />
  );
};

export default FormFieldSet;
