import { createContext, useContext } from "react";

export type TabsValue = string | number;

export type TabsConfig = {
  value: TabsValue;
  setValue: (v: TabsValue) => void;
  orientation: "horizontal" | "vertical";
  appearance: "underline" | "pill" | "segmented" | "outline" | "dot";
  density: "comfortable" | "compact";
  radius: "none" | "sm" | "md" | "lg" | "full" | number | undefined;
  indicator: { height?: number | string; color?: string; glow?: boolean } | undefined;
  appearanceOptions:
    | {
        underline?: {
          position?: "bottom" | "top";
          cap?: "square" | "round";
          offset?: number;
          widthStrategy?: "tab" | "label";
        };
        pill?: {
          elevated?: boolean;
        };
        outline?: {
          activeEmphasis?: "stroke" | "fill";
        };
      }
    | undefined;
  renderLazy: boolean;
  getIds: (v: TabsValue) => { tab: string; panel: string };
  isActive: (v: TabsValue) => boolean;
};

export const TabsContext = createContext<TabsConfig | null>(null);

export function useTabsContext() {
  const ctx = useContext(TabsContext);
  if (!ctx) throw new Error("oks-ui Tabs: TabsRoot is required");
  return ctx;
}
