import type {
  CSSProperties,
  ElementType,
  HTMLAttributes,
  ReactNode,
} from "react";
import React, { forwardRef, useEffect, useState } from "react";
import { clamp } from "../../utils";
import { Tooltip, type TooltipProps } from "../Tooltip";
import { AvatarIcon } from "./AvatarIcon";
import "./Avatar.module.css";
import "./AvatarGroup.module.css";

export type AvatarSize = "sm" | "md" | "lg";

export type AvatarColor =
  | "default"
  | "primary"
  | "secondary"
  | "info"
  | "success"
  | "warning"
  | "danger";

export type AvatarRadius = "none" | "sm" | "md" | "lg" | "full";

export type AvatarSlot = "base" | "img" | "fallback" | "name" | "icon";

export type AvatarColorDepth =
  | 50
  | 100
  | 200
  | 300
  | 400
  | 500
  | 600
  | 700
  | 800
  | 900
  | 950;

export type AvatarTooltip =
  | boolean
  | Omit<TooltipProps, "children" | "content">
  | {
      props?: Omit<TooltipProps, "children" | "content">;
      content?: ReactNode;
    };

export type AvatarProps<ImgComponent extends ElementType = "img"> = Omit<
  HTMLAttributes<HTMLDivElement>,
  "color"
> & {
  name?: string;
  src?: string;
  size?: AvatarSize;
  color?: AvatarColor;
  radius?: AvatarRadius;
  colorDepth?: AvatarColorDepth;
  isBordered?: boolean;
  isDisabled?: boolean;
  isFocusable?: boolean;
  showFallback?: boolean;
  icon?: ReactNode;
  fallback?: ReactNode;
  tooltip?: AvatarTooltip;
  ImgComponent?: ImgComponent;
  imgProps?: Omit<
    React.ComponentPropsWithoutRef<ImgComponent>,
    "src" | "children"
  >;
  classNames?: Partial<Record<AvatarSlot, string>>;
};

export type AvatarGroupProps = Omit<
  HTMLAttributes<HTMLDivElement>,
  "color" | "children"
> & {
  children?: ReactNode;
  max?: number;
  total?: number;
  size?: AvatarSize;
  color?: AvatarColor;
  radius?: AvatarRadius;
  isGrid?: boolean;
  isDisabled?: boolean;
  isBordered?: boolean;
  renderCount?: (count: number) => ReactNode;
  classNames?: Partial<Record<"base" | "count", string>>;
};

function mergeClassName(a: unknown, b: unknown) {
  const sa = typeof a === "string" ? a : "";
  const sb = typeof b === "string" ? b : "";
  return [sa, sb].filter(Boolean).join(" ");
}

const ALLOWED_DEPTHS = [
  50, 100, 200, 300, 400, 500, 600, 700, 800, 900, 950,
] as const;

function snapDepth(input: number) {
  const clamped = clamp(input, 50, 950);
  const first: number = ALLOWED_DEPTHS[0] ?? 500;
  let best: number = first;
  let bestDiff = Math.abs(best - clamped);
  for (const d of ALLOWED_DEPTHS) {
    const diff = Math.abs(d - clamped);
    if (diff < bestDiff) {
      best = d;
      bestDiff = diff;
    }
  }
  return best;
}

function getColorVar(color: string, depth: number) {
  const fallback = `var(--oks-color-default-${depth}, var(--oks-color-primary-${depth}, #3b82f6))`;
  if (color === "default") return fallback;
  return `var(--oks-color-${color}-${depth}, ${fallback})`;
}

function getBorderVar(color: string, depth: number) {
  return getColorVar(color, depth);
}

function getInitials(name: string | undefined) {
  const value = typeof name === "string" ? name.trim() : "";
  if (!value) return "";
  const parts = value.split(/\s+/).filter(Boolean);
  if (parts.length === 0) return "";
  const a = parts[0]?.[0] ?? "";
  const b = parts.length > 1 ? (parts[parts.length - 1]?.[0] ?? "") : "";
  return (a + b).toUpperCase();
}

function formatOverflowCount(num: number) {
  const n = Math.floor(Math.abs(num));
  if (n < 1000) return `+${n}`;
  if (n < 1000000) return `+${Math.floor(n / 1000)}K`;
  if (n < 1000000000) return `+${Math.floor(n / 1000000)}M`;
  return `+${Math.floor(n / 1000000000)}B`;
}

export const Avatar = forwardRef<HTMLDivElement, AvatarProps>((props, ref) => {
  const {
    name,
    src,
    size = "md",
    color = "default",
    radius = "full",
    colorDepth = 500,
    isBordered = false,
    isDisabled = false,
    isFocusable = false,
    showFallback = false,
    icon,
    fallback,
    tooltip = false,
    ImgComponent = "img",
    imgProps,
    classNames,
    className,
    style,
    ...rest
  } = props;

  const resolvedName = typeof name === "string" ? name : "";
  const resolvedDisabled = isDisabled;
  const resolvedColor = color;
  const resolvedDepth =
    typeof colorDepth === "number" ? snapDepth(colorDepth) : 500;
  const solidFg = resolvedDepth <= 400 ? "#000" : "#fff";

  const [imgFailed, setImgFailed] = useState(false);
  useEffect(() => setImgFailed(false), [src]);

  const shouldShowFallback = (() => {
    if (!src) return true;
    if (!imgFailed) return false;
    return showFallback === true;
  })();

  const avatarVars: CSSProperties = {
    ["--oks-avatar-bg" as any]: getColorVar(resolvedColor, resolvedDepth),
    ["--oks-avatar-bg-50" as any]: getColorVar(resolvedColor, 50),
    ["--oks-avatar-fg" as any]: solidFg,
    ["--oks-avatar-border" as any]: getBorderVar(resolvedColor, resolvedDepth),
  } as unknown as CSSProperties;

  const rootStyle: CSSProperties = {
    ...avatarVars,
    ...(style ?? {}),
  };

  const userAriaLabel = rest["aria-label"];
  const resolvedAriaLabel =
    typeof userAriaLabel === "string"
      ? userAriaLabel
      : resolvedName || undefined;

  const resolvedTabIndex =
    isFocusable === true && rest.tabIndex === undefined ? 0 : rest.tabIndex;

  const baseClassName = mergeClassName(
    mergeClassName("oksAvatar", classNames?.base),
    className,
  );

  const fallbackContent =
    fallback !== undefined && fallback !== null ? (
      fallback
    ) : resolvedName.trim().length > 0 ? (
      <span
        className={mergeClassName("oksAvatarInitials", classNames?.name)}
        aria-hidden="true"
      >
        {getInitials(resolvedName)}
      </span>
    ) : (
      <span
        className={mergeClassName("oksAvatarFallbackIcon", classNames?.icon)}
        aria-hidden="true"
      >
        {icon ?? <AvatarIcon />}
      </span>
    );

  const avatarElement = (
    <div
      {...rest}
      ref={ref}
      className={baseClassName}
      data-size={size}
      data-color={resolvedColor}
      data-radius={radius}
      data-bordered={isBordered ? "true" : undefined}
      data-focusable={isFocusable ? "true" : undefined}
      data-disabled={resolvedDisabled ? "true" : undefined}
      role={shouldShowFallback ? "img" : rest.role}
      aria-label={shouldShowFallback ? resolvedAriaLabel : rest["aria-label"]}
      tabIndex={resolvedDisabled ? rest.tabIndex : resolvedTabIndex}
      style={rootStyle}
    >
      {shouldShowFallback ? (
        <span
          className={mergeClassName("oksAvatarFallback", classNames?.fallback)}
        >
          {fallbackContent}
        </span>
      ) : (
        <ImgComponent
          {...(imgProps as any)}
          className={mergeClassName(
            mergeClassName("oksAvatarImage", classNames?.img),
            (imgProps as any)?.className,
          )}
          src={src}
          alt={(imgProps as any)?.alt ?? resolvedName}
          draggable={false}
          onError={(event: any) => {
            setImgFailed(true);
            (imgProps as any)?.onError?.(event);
          }}
        />
      )}
    </div>
  );

  const tooltipContent =
    tooltip === true
      ? resolvedName
      : typeof tooltip === "object" && tooltip !== null
        ? "content" in tooltip
          ? (tooltip.content ?? resolvedName)
          : resolvedName
        : null;

  const tooltipProps =
    typeof tooltip === "object" && tooltip !== null
      ? "props" in tooltip
        ? tooltip.props
        : tooltip
      : undefined;

  const hasTooltip =
    (tooltip === true || (typeof tooltip === "object" && tooltip !== null)) &&
    typeof tooltipContent === "string"
      ? tooltipContent.trim().length > 0
      : tooltipContent !== null && tooltipContent !== undefined;

  if (!hasTooltip) return avatarElement;

  const tooltipNode = resolvedDisabled ? (
    <span className="oksAvatarTooltipWrapper">{avatarElement}</span>
  ) : (
    avatarElement
  );

  return (
    <Tooltip {...(tooltipProps as any)} content={tooltipContent}>
      {tooltipNode}
    </Tooltip>
  );
});

Avatar.displayName = "Avatar";

export const AvatarGroup = forwardRef<HTMLDivElement, AvatarGroupProps>(
  (props, ref) => {
    const {
      children,
      max = 5,
      total,
      size = "md",
      color = "default",
      radius = "full",
      isGrid = false,
      isDisabled,
      isBordered = false,
      renderCount,
      classNames,
      className,
      style,
      ...rest
    } = props;

    const childrenArray = React.Children.toArray(children);
    const resolvedMax = Math.max(0, Math.floor(max));

    const overflowCount =
      typeof total === "number"
        ? total - resolvedMax
        : childrenArray.length - resolvedMax;
    const resolvedOverflow = overflowCount > 0 ? overflowCount : 0;

    const rootStyle: CSSProperties = {
      ...(style ?? {}),
    };

    const rootClassName = mergeClassName(
      mergeClassName("oksAvatarGroup", classNames?.base),
      className,
    );

    return (
      <div
        {...rest}
        ref={ref}
        className={rootClassName}
        data-grid={isGrid ? "true" : undefined}
        data-color={color}
        data-radius={radius}
        data-bordered={isBordered ? "true" : undefined}
        data-disabled={isDisabled ? "true" : undefined}
        style={rootStyle}
      >
        <div
          className="oksAvatarGroupStack"
          data-grid={isGrid ? "true" : undefined}
        >
          {childrenArray.slice(0, resolvedMax).map((child, index) => {
            if (React.isValidElement(child)) {
              const childAny: any = child;
              const childProps: any = {
                size,
              };
              if (childAny.props?.radius === undefined)
                childProps.radius = radius;
              if (childAny.props?.isBordered === undefined)
                childProps.isBordered = isBordered;
              if (childAny.props?.isDisabled === undefined) {
                childProps.isDisabled = isDisabled;
              }
              if (childAny.props?.color === undefined) childProps.color = color;
              return (
                <div key={index} className="oksAvatarGroupItem">
                  {React.cloneElement(child as any, childProps)}
                </div>
              );
            }
            return (
              <div key={index} className="oksAvatarGroupItem">
                {child}
              </div>
            );
          })}
        </div>
        {resolvedOverflow > 0 ? (
          <span
            className={mergeClassName(
              "oksAvatarGroupOverflowText",
              classNames?.count,
            )}
            style={
              {
                ["--oks-avatar-group-count-color" as any]: getColorVar(
                  color,
                  600,
                ),
              } as unknown as CSSProperties
            }
          >
            {renderCount
              ? renderCount(resolvedOverflow)
              : formatOverflowCount(resolvedOverflow)}
          </span>
        ) : null}
      </div>
    );
  },
);

AvatarGroup.displayName = "AvatarGroup";
