import type { CSSProperties, ReactNode, TextareaHTMLAttributes } from "react";
import { forwardRef, useId, useMemo } from "react";
import type {
  FormElementLabelPlacement,
  FormElementSize,
  FormElementTone,
  FormElementVariant,
} from "../types";
import { getToneVar, mergeClassName } from "../internal";
import "./TextAreaField.module.css";

export type TextAreaFieldProps = Omit<
  TextareaHTMLAttributes<HTMLTextAreaElement>,
  "color"
> & {
  label?: ReactNode;
  labelPlacement?: FormElementLabelPlacement;
  description?: ReactNode;
  error?: ReactNode | boolean;
  size?: FormElementSize;
  variant?: FormElementVariant;
  tone?: FormElementTone;
  colorDepth?: number;
  style?: CSSProperties;
};

export const TextAreaField = forwardRef<HTMLTextAreaElement, TextAreaFieldProps>(
  (props, ref) => {
    const {
      label,
      labelPlacement = "top",
      description,
      error,
      size = "md",
      variant = "outline",
      tone = "primary",
      colorDepth = 500,
      className,
      id,
      required,
      disabled,
      placeholder,
      rows = 4,
      style,
      ...rest
    } = props;

    const reactId = useId();
    const fieldId = id ?? `oks-text-area-${reactId}`;

    const describedBy = rest["aria-describedby"];
    const descriptionId = description ? `${fieldId}-description` : undefined;
    const errorId =
      error && error !== true ? `${fieldId}-error-message` : undefined;
    const ariaDescribedBy = [describedBy, descriptionId, errorId]
      .filter(Boolean)
      .join(" ");

    const isInvalid = Boolean(error);

    const resolvedPlaceholder = useMemo(() => {
      if (labelPlacement !== "floating") return placeholder;
      if (!label) return placeholder;
      if (placeholder !== undefined) return placeholder;
      return " ";
    }, [labelPlacement, label, placeholder]);

    const toneVars: CSSProperties = {
      "--oks-text-area-tone": getToneVar(tone, colorDepth),
    } as unknown as CSSProperties;

    const topLabel = labelPlacement === "top" ? label : null;
    const floatingLabel = labelPlacement === "floating" ? label : null;

    return (
      <div
        className={mergeClassName("oksTextAreaField", className)}
        data-size={size}
        data-variant={variant}
        data-tone={tone}
        data-label-placement={labelPlacement}
        data-invalid={isInvalid ? "true" : "false"}
        data-disabled={disabled ? "true" : "false"}
        style={{ ...toneVars, ...style }}
      >
        {topLabel ? (
          <label className="oksTextAreaFieldLabel" htmlFor={fieldId}>
            {topLabel}
            {required ? <span aria-hidden="true">*</span> : null}
          </label>
        ) : null}

        <div className="oksTextAreaFieldControl">
          <textarea
            {...rest}
            ref={ref}
            id={fieldId}
            required={required}
            disabled={disabled}
            placeholder={resolvedPlaceholder}
            rows={rows}
            className="oksTextAreaFieldInput"
            aria-invalid={isInvalid ? "true" : undefined}
            aria-describedby={ariaDescribedBy || undefined}
            aria-errormessage={errorId}
          />

          {floatingLabel ? (
            <label className="oksTextAreaFieldLabel" htmlFor={fieldId}>
              {floatingLabel}
              {required ? <span aria-hidden="true">*</span> : null}
            </label>
          ) : null}
        </div>

        {description ? (
          <div id={descriptionId} className="oksTextAreaFieldDescription">
            {description}
          </div>
        ) : null}

        {error && error !== true ? (
          <div id={errorId} className="oksTextAreaFieldError" role="alert">
            {error}
          </div>
        ) : null}
      </div>
    );
  },
);

TextAreaField.displayName = "TextAreaField";

