import type {
  CSSProperties,
  FocusEvent as ReactFocusEvent,
  Key,
  KeyboardEvent,
  MouseEvent as ReactMouseEvent,
  MutableRefObject,
  PointerEvent as ReactPointerEvent,
  ReactElement,
  ReactNode,
} from "react";
import {
  Children,
  cloneElement,
  createContext,
  forwardRef,
  isValidElement,
  useCallback,
  useContext,
  useEffect,
  useId,
  useMemo,
  useRef,
  useState,
} from "react";
import { Portal } from "../../primitives/Portal";
import type { TooltipAlign, TooltipSide } from "../Tooltip/tooltipPositioning";
import { computeTooltipPosition } from "../Tooltip/tooltipPositioning";

import "./Dropdown.module.css";

export type DropdownPlacement =
  | "top"
  | "bottom"
  | "left"
  | "right"
  | "top-start"
  | "top-end"
  | "bottom-start"
  | "bottom-end"
  | "left-start"
  | "left-end"
  | "right-start"
  | "right-end";

export type DropdownMenuVariant =
  | "solid"
  | "bordered"
  | "light"
  | "flat"
  | "faded"
  | "shadow";

export type DropdownColor =
  | "default"
  | "primary"
  | "secondary"
  | "success"
  | "warning"
  | "danger";

export type DropdownSelectionMode = "none" | "single" | "multiple";

export type DropdownProps = {
  children?: ReactNode;
  isOpen?: boolean;
  defaultOpen?: boolean;
  onOpenChange?: (isOpen: boolean) => void;
  placement?: DropdownPlacement;
  offset?: number;
  containerPadding?: number;
  shouldFlip?: boolean;
  portalContainer?: Element | DocumentFragment | null;
  isDismissable?: boolean;
  isKeyboardDismissDisabled?: boolean;
  shouldCloseOnInteractOutside?: (target: Element) => boolean;
  closeOnSelect?: boolean;
  classNames?: Partial<Record<"base" | "content", string>>;
  className?: string;
  style?: CSSProperties;
};

export type DropdownTriggerProps = {
  children: ReactElement;
};

export type DropdownMenuClassNames = Partial<
  Record<"base" | "list" | "emptyContent", string>
>;

export type DropdownMenuProps<T = unknown> = {
  children?: ReactNode | ((item: T) => ReactElement);
  items?: Iterable<T>;
  variant?: DropdownMenuVariant;
  color?: DropdownColor;
  selectionMode?: DropdownSelectionMode;
  selectedKeys?: "all" | Iterable<Key>;
  disabledKeys?: Iterable<Key>;
  defaultSelectedKeys?: "all" | Iterable<Key>;
  disallowEmptySelection?: boolean;
  autoFocus?: boolean | "first" | "last";
  topContent?: ReactNode;
  bottomContent?: ReactNode;
  emptyContent?: ReactNode;
  hideEmptyContent?: boolean;
  hideSelectedIcon?: boolean;
  shouldFocusWrap?: boolean;
  closeOnSelect?: boolean;
  disableAnimation?: boolean;
  classNames?: DropdownMenuClassNames;
  itemClasses?: Partial<Record<DropdownItemSlot, string>>;
  onAction?: (key: Key) => void;
  onSelectionChange?: (
    keys:
      | "all"
      | (Set<Key> & { anchorKey?: Key; currentKey?: Key }),
  ) => void;
  onClose?: () => void;
};

export type DropdownItemSlot =
  | "base"
  | "wrapper"
  | "title"
  | "description"
  | "shortcut"
  | "selectedIcon";

export type DropdownItemProps = {
  children?: ReactNode;
  title?: string | ReactNode;
  textValue?: string;
  description?: string | ReactNode;
  shortcut?: string | ReactNode;
  startContent?: ReactNode;
  endContent?: ReactNode;
  selectedIcon?: ReactNode;
  showDivider?: boolean;
  href?: string;
  target?: string;
  rel?: string;
  download?: boolean | string;
  ping?: string;
  referrerPolicy?: string;
  isDisabled?: boolean;
  isSelected?: boolean;
  isReadOnly?: boolean;
  hideSelectedIcon?: boolean;
  closeOnSelect?: boolean;
  classNames?: Partial<Record<DropdownItemSlot, string>>;
  onAction?: () => void;
  onClose?: () => void;
  onPress?: (e: DropdownPressEvent) => void;
  onPressStart?: (e: DropdownPressEvent) => void;
  onPressEnd?: (e: DropdownPressEvent) => void;
  onPressChange?: (isPressed: boolean) => void;
  onPressUp?: (e: DropdownPressEvent) => void;
  onKeyDown?: (e: KeyboardEvent<HTMLElement>) => void;
  onKeyUp?: (e: KeyboardEvent<HTMLElement>) => void;
  onClick?: (e: ReactMouseEvent<HTMLElement>) => void;
  itemKey?: Key;
};

export type DropdownSectionSlot = "base" | "heading" | "group" | "divider";

export type DropdownSectionProps = {
  children?: ReactNode | ((item: any) => ReactElement);
  title?: string;
  items?: Iterable<unknown>;
  ["aria-label"]?: string;
  hideSelectedIcon?: boolean;
  showDivider?: boolean;
  dividerProps?: unknown;
  classNames?: Partial<Record<DropdownSectionSlot, string>>;
  itemClasses?: Partial<Record<DropdownItemSlot, string>>;
};

export type DropdownPressEvent =
  | ReactMouseEvent<HTMLElement>
  | ReactPointerEvent<HTMLElement>
  | KeyboardEvent<HTMLElement>
  | ReactFocusEvent<HTMLElement>;

function mergeClassName(a: unknown, b: unknown) {
  const sa = typeof a === "string" ? a : "";
  const sb = typeof b === "string" ? b : "";
  return [sa, sb].filter(Boolean).join(" ");
}

function getColorVar(color: DropdownColor, depth: number) {
  const fallback = `var(--oks-color-default-${depth}, var(--oks-color-primary-${depth}, #3b82f6))`;
  if (color === "default") return fallback;
  return `var(--oks-color-${color}-${depth}, ${fallback})`;
}

function mergeRefs<T>(
  ...refs: Array<
    ((node: T | null) => void) | MutableRefObject<T | null> | null | undefined
  >
) {
  return (node: T | null) => {
    for (const ref of refs) {
      if (!ref) continue;
      if (typeof ref === "function") ref(node);
      else ref.current = node;
    }
  };
}

function normalizeElementKey(key: string) {
  return key.startsWith(".$") ? key.slice(2) : key;
}

function parsePlacement(placement: DropdownPlacement) {
  const [rawSide, rawAlign] = placement.split("-") as [
    TooltipSide | undefined,
    TooltipAlign | undefined,
  ];
  const side: TooltipSide =
    rawSide === "top" ||
    rawSide === "bottom" ||
    rawSide === "left" ||
    rawSide === "right"
      ? rawSide
      : "bottom";
  const align: TooltipAlign =
    rawAlign === "start" || rawAlign === "end" ? rawAlign : "center";
  return { side, align };
}

type DropdownContextValue = {
  open: boolean;
  setOpen: (next: boolean, restoreFocus?: boolean) => void;
  toggle: () => void;
  openSourceRef: MutableRefObject<"pointer" | "keyboard" | "programmatic">;
  menuOnCloseRef: MutableRefObject<(() => void) | undefined>;
  placement: DropdownPlacement;
  offset: number;
  containerPadding: number;
  shouldFlip: boolean;
  portalContainer: Element | DocumentFragment | null | undefined;
  isDismissable: boolean;
  isKeyboardDismissDisabled: boolean;
  shouldCloseOnInteractOutside?: (target: Element) => boolean;
  closeOnSelect: boolean;
  triggerRef: MutableRefObject<HTMLElement | null>;
  menuRef: MutableRefObject<HTMLDivElement | null>;
  triggerId: string;
  menuId: string;
  baseClassNames?: Partial<Record<"base" | "content", string>>;
};

const DropdownContext = createContext<DropdownContextValue | null>(null);

function useDropdownContext() {
  const ctx = useContext(DropdownContext);
  if (!ctx) throw new Error("oks-ui Dropdown: missing context.");
  return ctx;
}

type ItemInfo = {
  key: Key;
  disabled: boolean;
  textValue: string;
};

type ParsedSection = {
  implicit?: boolean;
  title?: string;
  ariaLabel?: string;
  showDivider?: boolean;
  classNames?: Partial<Record<DropdownSectionSlot, string>>;
  hideSelectedIcon?: boolean;
  itemClasses?: Partial<Record<DropdownItemSlot, string>>;
  items: Array<{ key: Key; element: ReactElement<DropdownItemProps> }>;
};

type DropdownMenuContextValue = {
  disabledKeys: Set<Key>;
  selectionMode: DropdownSelectionMode;
  selectedKeys: "all" | Set<Key>;
  setSelectedKeys: (next: "all" | Set<Key>) => void;
  disallowEmptySelection: boolean;
  onAction?: (key: Key) => void;
  onSelectionChange?: (
    keys:
      | "all"
      | (Set<Key> & { anchorKey?: Key; currentKey?: Key }),
  ) => void;
  onClose?: () => void;
  onItemAction: (key: Key, item: DropdownItemProps) => void;
  closeOnSelect: boolean;
  hideSelectedIcon: boolean;
  setOpen: (next: boolean, restoreFocus?: boolean) => void;
  focusedKey: Key | null;
  setFocusedKey: (key: Key | null) => void;
  registerItemRef: (key: Key, node: HTMLElement | null, info: ItemInfo) => void;
  itemClasses?: Partial<Record<DropdownItemSlot, string>>;
  menuVariant: DropdownMenuVariant;
  menuColor: DropdownColor;
  shouldFocusWrap: boolean;
  disableAnimation: boolean;
};

const DropdownMenuContext = createContext<DropdownMenuContextValue | null>(null);

function useDropdownMenuContext() {
  const ctx = useContext(DropdownMenuContext);
  if (!ctx) throw new Error("oks-ui DropdownMenu: missing context.");
  return ctx;
}

function isDropdownItemElement(node: unknown): node is ReactElement<DropdownItemProps> {
  return isValidElement(node) && node.type === DropdownItem;
}

function isDropdownSectionElement(
  node: unknown,
): node is ReactElement<DropdownSectionProps> {
  return isValidElement(node) && node.type === DropdownSection;
}

function getItemTextValue(key: Key, props: DropdownItemProps) {
  if (typeof props.textValue === "string") return props.textValue;
  if (typeof props.title === "string") return props.title;
  if (typeof props.children === "string") return props.children;
  return String(key);
}

function keyFromElement(el: ReactElement) {
  const k = el.key;
  if (k === null || k === undefined) return null;
  if (typeof k === "string") {
    const normalized = normalizeElementKey(k).trim();
    return normalized.length > 0 ? normalized : null;
  }
  return k;
}

function getFirstEnabled(keys: Key[], disabled: Set<Key>) {
  for (const k of keys) {
    if (!disabled.has(k)) return k;
  }
  return null;
}

function getLastEnabled(keys: Key[], disabled: Set<Key>) {
  for (let i = keys.length - 1; i >= 0; i--) {
    const k = keys[i];
    if (k && !disabled.has(k)) return k;
  }
  return null;
}

function getNextEnabled(
  keys: Key[],
  disabled: Set<Key>,
  from: Key | null,
  dir: 1 | -1,
  wrap: boolean,
) {
  if (keys.length === 0) return null;
  const startIdx = from !== null ? keys.indexOf(from) : -1;
  if (!wrap) {
    for (let idx = startIdx + dir; idx >= 0 && idx < keys.length; idx += dir) {
      const k = keys[idx];
      if (k !== null && k !== undefined && !disabled.has(k)) return k;
    }
    return null;
  }

  let idx = startIdx;
  for (let i = 0; i < keys.length; i++) {
    idx = (idx + dir + keys.length) % keys.length;
    const k = keys[idx];
    if (k !== null && k !== undefined && !disabled.has(k)) return k;
  }
  return null;
}

function isPrintableKey(e: KeyboardEvent) {
  const key = e.key;
  if (key.length !== 1) return false;
  if (e.ctrlKey || e.metaKey || e.altKey) return false;
  return true;
}

function toKeySet(value: Iterable<Key> | undefined) {
  const set = new Set<Key>();
  for (const k of value ?? []) set.add(k);
  return set;
}

export const Dropdown = forwardRef<HTMLDivElement, DropdownProps>((props, ref) => {
  const {
    children,
    isOpen,
    defaultOpen = false,
    onOpenChange,
    placement = "bottom-start",
    offset = 8,
    containerPadding = 8,
    shouldFlip = true,
    portalContainer,
    isDismissable = true,
    isKeyboardDismissDisabled = false,
    shouldCloseOnInteractOutside,
    closeOnSelect = true,
    classNames,
    className,
    style,
  } = props;

  const [uncontrolledOpen, setUncontrolledOpen] = useState(defaultOpen);
  const open = isOpen !== undefined ? isOpen : uncontrolledOpen;

  const triggerRef = useRef<HTMLElement | null>(null);
  const menuRef = useRef<HTMLDivElement | null>(null);
  const openSourceRef = useRef<"pointer" | "keyboard" | "programmatic">("programmatic");
  const menuOnCloseRef = useRef<(() => void) | undefined>(undefined);

  const id = useId();
  const triggerId = `oks-dropdown-trigger-${id}`;
  const menuId = `oks-dropdown-menu-${id}`;

  const setOpen = useCallback(
    (next: boolean, restoreFocus = true) => {
      if (!next) menuOnCloseRef.current?.();
      if (isOpen === undefined) setUncontrolledOpen(next);
      onOpenChange?.(next);
      if (!next && restoreFocus) {
        const node = triggerRef.current;
        if (node) {
          window.requestAnimationFrame(() => {
            node.focus?.();
          });
        }
      }
    },
    [isOpen, onOpenChange],
  );

  const toggle = useCallback(() => setOpen(!open, false), [open, setOpen]);

  useEffect(() => {
    if (!open) return;
    const onKeyDown = (e: KeyboardEvent) => {
      if (e.key !== "Escape") return;
      if (isKeyboardDismissDisabled) return;
      e.preventDefault();
      setOpen(false, true);
    };

    const onPointerDown = (e: PointerEvent) => {
      if (!isDismissable) return;
      const target = e.target;
      if (!(target instanceof Element)) return;
      const triggerEl = triggerRef.current;
      const menuEl = menuRef.current;
      if (triggerEl && triggerEl.contains(target)) return;
      if (menuEl && menuEl.contains(target)) return;
      if (shouldCloseOnInteractOutside && !shouldCloseOnInteractOutside(target))
        return;
      setOpen(false, true);
    };

    document.addEventListener("keydown", onKeyDown as any);
    document.addEventListener("pointerdown", onPointerDown, { capture: true });
    return () => {
      document.removeEventListener("keydown", onKeyDown as any);
      document.removeEventListener("pointerdown", onPointerDown, { capture: true } as any);
    };
  }, [
    open,
    isDismissable,
    isKeyboardDismissDisabled,
    setOpen,
    shouldCloseOnInteractOutside,
  ]);

  const ctx: DropdownContextValue = {
    open,
    setOpen,
    toggle,
    openSourceRef,
    menuOnCloseRef,
    placement,
    offset,
    containerPadding,
    shouldFlip,
    portalContainer,
    isDismissable,
    isKeyboardDismissDisabled,
    ...(shouldCloseOnInteractOutside
      ? { shouldCloseOnInteractOutside }
      : {}),
    closeOnSelect,
    triggerRef,
    menuRef,
    triggerId,
    menuId,
    ...(classNames ? { baseClassNames: classNames } : {}),
  };

  return (
    <DropdownContext.Provider value={ctx}>
      <div
        ref={ref}
        className={mergeClassName(mergeClassName("oksDropdown", classNames?.base), className)}
        style={style}
      >
        <div className={mergeClassName("oksDropdownContent", classNames?.content)}>
          {children}
        </div>
      </div>
    </DropdownContext.Provider>
  );
});

Dropdown.displayName = "Dropdown";

export const DropdownTrigger = forwardRef<HTMLElement, DropdownTriggerProps>(
  (props, forwardedRef) => {
    const { children } = props;
    const ctx = useDropdownContext();

    const childAny: any = children;
    const childRef = childAny?.ref;

    const handleClick = (e: any) => {
      childAny?.props?.onClick?.(e);
      if (e?.defaultPrevented) return;
      ctx.openSourceRef.current = "pointer";
      ctx.toggle();
    };

    const handleKeyDown = (e: any) => {
      childAny?.props?.onKeyDown?.(e);
      if (e?.defaultPrevented) return;
      if (e.key === "Enter" || e.key === " " || e.key === "ArrowDown") {
        e.preventDefault();
        ctx.openSourceRef.current = "keyboard";
        ctx.setOpen(true, false);
      }
    };

    return cloneElement(children, {
      id: ctx.triggerId,
      "aria-haspopup": "menu",
      "aria-expanded": ctx.open ? "true" : "false",
      "aria-controls": ctx.menuId,
      onClick: handleClick,
      onKeyDown: handleKeyDown,
      ref: mergeRefs(childRef, forwardedRef as any, (node: any) => {
        ctx.triggerRef.current = node instanceof HTMLElement ? node : null;
      }),
      className: mergeClassName("oksDropdownTrigger", childAny?.props?.className),
    });
  },
);

DropdownTrigger.displayName = "DropdownTrigger";

export const DropdownMenu = <T,>(props: DropdownMenuProps<T>) => {
  const {
    children,
    items,
    onAction,
    disabledKeys,
    onClose,
    selectionMode = "none",
    selectedKeys,
    defaultSelectedKeys,
    onSelectionChange,
    disallowEmptySelection = false,
    variant = "solid",
    color = "default",
    autoFocus = false,
    hideEmptyContent = false,
    hideSelectedIcon = false,
    shouldFocusWrap = false,
    closeOnSelect,
    disableAnimation = false,
    classNames,
    itemClasses,
    topContent,
    bottomContent,
    emptyContent = "No items.",
  } = props;

  const dropdown = useDropdownContext();
  const effectiveCloseOnSelect = closeOnSelect ?? dropdown.closeOnSelect;
  const disabledSet = useMemo(() => toKeySet(disabledKeys), [disabledKeys]);
  const toneVars = useMemo(
    () =>
      ({
        "--oks-dropdown-tone": getColorVar(color, 500),
        "--oks-dropdown-tone-600": getColorVar(color, 600),
      }) as unknown as CSSProperties,
    [color],
  );

  const [uncontrolledSelected, setUncontrolledSelected] = useState<"all" | Set<Key>>(
    () => (defaultSelectedKeys === "all" ? "all" : toKeySet(defaultSelectedKeys)),
  );

  const resolvedSelected = useMemo<"all" | Set<Key>>(() => {
    if (selectedKeys === "all") return "all";
    if (selectedKeys !== undefined) return toKeySet(selectedKeys);
    return uncontrolledSelected;
  }, [selectedKeys, uncontrolledSelected]);

  const setSelectedKeys = useCallback(
    (next: "all" | Set<Key>) => {
      if (selectedKeys === undefined) setUncontrolledSelected(next);
    },
    [selectedKeys],
  );

  const { side, align } = useMemo(
    () => parsePlacement(dropdown.placement),
    [dropdown.placement],
  );

  const [position, setPosition] = useState<{
    top: number;
    left: number;
    placedSide: TooltipSide;
    placedAlign: TooltipAlign;
  } | null>(null);

  const itemRefs = useRef(new Map<Key, HTMLElement>());
  const itemInfo = useRef(new Map<Key, ItemInfo>());
  const typeaheadRef = useRef<{ buffer: string; timer: number | null }>({
    buffer: "",
    timer: null,
  });
  const listRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    if (!dropdown.open) return;
    dropdown.menuOnCloseRef.current = onClose;
    return () => {
      if (dropdown.menuOnCloseRef.current === onClose) {
        dropdown.menuOnCloseRef.current = undefined;
      }
    };
  }, [dropdown.menuOnCloseRef, dropdown.open, onClose]);

  const updatePosition = useCallback(() => {
    const triggerEl = dropdown.triggerRef.current;
    const menuEl = dropdown.menuRef.current;
    if (!triggerEl || !menuEl) return;
    const triggerRect = triggerEl.getBoundingClientRect();
    const tooltipRect = menuEl.getBoundingClientRect();

    const result = computeTooltipPosition({
      triggerRect,
      tooltipRect,
      side,
      align,
      offset: dropdown.offset,
      collisionPadding: dropdown.containerPadding,
      shouldFlip: dropdown.shouldFlip,
      arrowSize: 0,
      arrowPaddingX: 0,
      arrowPaddingY: 0,
      strategy: "fixed",
    });

    setPosition({
      top: result.top,
      left: result.left,
      placedSide: result.placedSide,
      placedAlign: align,
    });
  }, [
    align,
    dropdown.containerPadding,
    dropdown.offset,
    dropdown.shouldFlip,
    dropdown.triggerRef,
    dropdown.menuRef,
    side,
  ]);

  useEffect(() => {
    if (!dropdown.open) return;
    updatePosition();
    const onScroll = () => updatePosition();
    const onResize = () => updatePosition();
    window.addEventListener("scroll", onScroll, { passive: true, capture: true });
    window.addEventListener("resize", onResize, { passive: true });
    return () => {
      window.removeEventListener("scroll", onScroll, { capture: true } as any);
      window.removeEventListener("resize", onResize as any);
    };
  }, [dropdown.open, updatePosition]);

  useEffect(() => {
    if (!dropdown.open) return;
    const menuEl = dropdown.menuRef.current;
    if (!menuEl || typeof ResizeObserver === "undefined") return;
    const ro = new ResizeObserver(() => updatePosition());
    ro.observe(menuEl);
    return () => ro.disconnect();
  }, [dropdown.open, updatePosition]);

  const renderedSections: ParsedSection[] = useMemo(() => {
    if (items !== undefined) {
      const render = children as unknown;
      if (typeof render !== "function") return [];
      const outItems: Array<{ key: Key; element: ReactElement<DropdownItemProps> }> = [];
      for (const item of items as Iterable<unknown>) {
        const el = (render as (it: unknown) => ReactElement)(item);
        if (!isDropdownItemElement(el)) continue;
        const k = keyFromElement(el);
        if (!k) continue;
        outItems.push({ key: k, element: el });
      }
      return outItems.length > 0 ? [{ implicit: true, items: outItems }] : [];
    }

    const nodes = Children.toArray(children as ReactNode);
    const defaultItems: Array<{ key: Key; element: ReactElement<DropdownItemProps> }> = [];
    const sections: ParsedSection[] = [];

    for (const node of nodes) {
      if (isDropdownSectionElement(node)) {
        const sectionItems: Array<{ key: Key; element: ReactElement<DropdownItemProps> }> = [];

        if (node.props.items !== undefined) {
          const render = node.props.children as unknown;
          if (typeof render === "function") {
            for (const item of node.props.items as Iterable<unknown>) {
              const el = (render as (it: unknown) => ReactElement)(item);
              if (!isDropdownItemElement(el)) continue;
              const k = keyFromElement(el);
              if (!k) continue;
              sectionItems.push({ key: k, element: el });
            }
          }
        } else {
          for (const child of Children.toArray(node.props.children as ReactNode)) {
            if (!isDropdownItemElement(child)) continue;
            const k = keyFromElement(child);
            if (!k) continue;
            sectionItems.push({ key: k, element: child });
          }
        }

        sections.push({
          ...(node.props.title !== undefined ? { title: node.props.title } : {}),
          ...(typeof (node.props as any)["aria-label"] === "string"
            ? { ariaLabel: (node.props as any)["aria-label"] }
            : {}),
          ...(node.props.hideSelectedIcon !== undefined
            ? { hideSelectedIcon: node.props.hideSelectedIcon }
            : {}),
          ...(node.props.showDivider !== undefined
            ? { showDivider: node.props.showDivider }
            : {}),
          ...(node.props.classNames ? { classNames: node.props.classNames } : {}),
          ...(node.props.itemClasses ? { itemClasses: node.props.itemClasses } : {}),
          items: sectionItems,
        } satisfies ParsedSection);
        continue;
      }

      if (isDropdownItemElement(node)) {
        const k = keyFromElement(node);
        if (!k) continue;
        defaultItems.push({ key: k, element: node });
      }
    }

    const out: ParsedSection[] = [];
    if (defaultItems.length > 0) out.push({ implicit: true, items: defaultItems });
    for (const s of sections) out.push(s);
    return out;
  }, [children, items]);

  const flattened = useMemo(() => {
    const list: Array<{ key: Key; element: ReactElement<DropdownItemProps> }> = [];
    for (const section of renderedSections) {
      for (const item of section.items) list.push(item);
    }
    return list;
  }, [renderedSections]);

  const keys = useMemo(() => flattened.map((it) => it.key), [flattened]);

  const itemPropsByKey = useMemo(() => {
    const map = new Map<Key, DropdownItemProps>();
    for (const it of flattened) map.set(it.key, it.element.props);
    return map;
  }, [flattened]);

  const computedDisabled = useMemo(() => {
    const set = new Set<Key>(disabledSet);
    for (const it of flattened) {
      if (it.element.props.isDisabled) set.add(it.key);
    }
    return set;
  }, [disabledSet, flattened]);

  const [focusedKey, setFocusedKey] = useState<Key | null>(null);

  const registerItemRef = useCallback((key: Key, node: HTMLElement | null, info: ItemInfo) => {
    if (node) itemRefs.current.set(key, node);
    else itemRefs.current.delete(key);
    itemInfo.current.set(key, info);
  }, []);

  const focusKey = useCallback(
    (key: Key | null) => {
      setFocusedKey(key);
      if (key === null) return;
      const node = itemRefs.current.get(key);
      if (node) node.focus();
    },
    [setFocusedKey],
  );

  useEffect(() => {
    if (!dropdown.open) return;
    const openedFromKeyboard = dropdown.openSourceRef.current === "keyboard";
    const requested =
      openedFromKeyboard && autoFocus === false ? "first" : autoFocus;

    const initial =
      requested === true || requested === "first"
        ? getFirstEnabled(keys, computedDisabled)
        : requested === "last"
          ? getLastEnabled(keys, computedDisabled)
          : null;

    setFocusedKey(initial);
    window.requestAnimationFrame(() => {
      if (initial !== null) itemRefs.current.get(initial)?.focus();
      else listRef.current?.focus();
    });
  }, [autoFocus, computedDisabled, dropdown.open, dropdown.openSourceRef, keys]);

  const handleItemAction = useCallback(
    (key: Key, item: DropdownItemProps) => {
      if (computedDisabled.has(key)) return;

      item.onAction?.();
      onAction?.(key);

      if (selectionMode !== "none" && item.isReadOnly !== true) {
        const enabledKeys = keys.filter((k) => !computedDisabled.has(k));
        const current =
          resolvedSelected === "all" ? new Set<Key>(enabledKeys) : new Set<Key>(resolvedSelected);

        let next: "all" | Set<Key> = current;

        if (selectionMode === "single") {
          const isAlreadySelected = current.has(key);
          current.clear();
          if (!(isAlreadySelected && disallowEmptySelection === false)) {
            current.add(key);
          }
        } else {
          if (current.has(key)) {
            if (disallowEmptySelection === false || current.size > 1) current.delete(key);
          } else {
            current.add(key);
          }
        }

        next = current;
        setSelectedKeys(next);

        if (onSelectionChange) {
          const payload = next as any;
          (payload as any).anchorKey = key;
          (payload as any).currentKey = key;
          onSelectionChange(payload as any);
        }
      }

      const shouldClose = item.closeOnSelect ?? effectiveCloseOnSelect;
      if (shouldClose) {
        dropdown.setOpen(false, true);
        item.onClose?.();
      }
    },
    [
      effectiveCloseOnSelect,
      computedDisabled,
      disallowEmptySelection,
      dropdown,
      keys,
      onAction,
      onClose,
      onSelectionChange,
      resolvedSelected,
      selectionMode,
      setSelectedKeys,
    ],
  );

  const handleKeyDown = (e: any) => {
    if (e.key === "ArrowDown") {
      e.preventDefault();
      focusKey(getNextEnabled(keys, computedDisabled, focusedKey, 1, shouldFocusWrap));
      return;
    }
    if (e.key === "ArrowUp") {
      e.preventDefault();
      focusKey(getNextEnabled(keys, computedDisabled, focusedKey, -1, shouldFocusWrap));
      return;
    }
    if (e.key === "Home") {
      e.preventDefault();
      focusKey(getFirstEnabled(keys, computedDisabled));
      return;
    }
    if (e.key === "End") {
      e.preventDefault();
      focusKey(getLastEnabled(keys, computedDisabled));
      return;
    }
    if (e.key === "Enter" || e.key === " ") {
      e.preventDefault();
      if (focusedKey !== null) {
        const itemProps = itemPropsByKey.get(focusedKey);
        if (itemProps) handleItemAction(focusedKey, itemProps);
      }
      return;
    }
    if (isPrintableKey(e)) {
      const nextBuffer = `${typeaheadRef.current.buffer}${e.key}`.toLowerCase();
      if (typeaheadRef.current.timer) window.clearTimeout(typeaheadRef.current.timer);
      typeaheadRef.current.buffer = nextBuffer;
      typeaheadRef.current.timer = window.setTimeout(() => {
        typeaheadRef.current.buffer = "";
        typeaheadRef.current.timer = null;
      }, 350);

      const startIdx = focusedKey !== null ? keys.indexOf(focusedKey) : -1;
      const len = keys.length;
      for (let i = 1; i <= len; i++) {
        const idx = (startIdx + i) % len;
        const k = keys[idx];
        if (k === null || k === undefined || computedDisabled.has(k)) continue;
        const tv = itemInfo.current.get(k)?.textValue ?? String(k);
        if (tv.toLowerCase().startsWith(nextBuffer)) {
          focusKey(k);
          break;
        }
      }
    }
  };

  const menuCtx: DropdownMenuContextValue = {
    disabledKeys: computedDisabled,
    selectionMode,
    selectedKeys: resolvedSelected,
    setSelectedKeys,
    disallowEmptySelection,
    ...(onAction ? { onAction } : {}),
    ...(onSelectionChange ? { onSelectionChange } : {}),
    ...(onClose ? { onClose } : {}),
    onItemAction: handleItemAction,
    closeOnSelect: effectiveCloseOnSelect,
    hideSelectedIcon,
    setOpen: dropdown.setOpen,
    focusedKey,
    setFocusedKey,
    registerItemRef,
    ...(itemClasses ? { itemClasses } : {}),
    menuVariant: variant,
    menuColor: color,
    shouldFocusWrap,
    disableAnimation,
  };

  if (!dropdown.open) return null;

  const hasItems = flattened.length > 0;
  const placementLabel =
    position === null ? dropdown.placement : `${position.placedSide}-${position.placedAlign}`;

  return (
    <Portal container={dropdown.portalContainer}>
      <DropdownMenuContext.Provider value={menuCtx}>
        <div
          ref={(node) => {
            dropdown.menuRef.current = node;
          }}
          id={dropdown.menuId}
          className={mergeClassName("oksDropdownMenu", classNames?.base)}
          data-open="true"
          data-placement={placementLabel}
          data-variant={variant}
          data-color={color}
          style={
            {
              ...toneVars,
              position: "fixed",
              top: position?.top ?? -9999,
              left: position?.left ?? -9999,
            } as CSSProperties
          }
        >
          {topContent !== undefined && topContent !== null ? (
            <div className="oksDropdownTopContent">{topContent}</div>
          ) : null}

          <div
            ref={listRef}
            role="menu"
            aria-labelledby={dropdown.triggerId}
            className={mergeClassName("oksDropdownList", classNames?.list)}
            tabIndex={-1}
            onKeyDown={handleKeyDown}
          >
            {hasItems ? (
              renderedSections.map((section, idx) => (
                <DropdownSectionView key={idx} section={section} />
              ))
            ) : hideEmptyContent ? null : (
              <div className={mergeClassName("oksDropdownEmpty", classNames?.emptyContent)}>
                {emptyContent ?? null}
              </div>
            )}
          </div>

          {bottomContent !== undefined && bottomContent !== null ? (
            <div className="oksDropdownBottomContent">{bottomContent}</div>
          ) : null}
        </div>
      </DropdownMenuContext.Provider>
    </Portal>
  );
};

function DropdownSectionView({ section }: { section: ParsedSection }) {
  const needsLabel =
    section.implicit === true ? false : section.title === undefined || section.title === null;
  const label = needsLabel ? section.ariaLabel : undefined;

  const nodeEnv = (globalThis as any)?.process?.env?.NODE_ENV;
  if (nodeEnv !== "production") {
    if (needsLabel && typeof label !== "string") {
      throw new Error(
        'oks-ui DropdownSection: when "title" is not provided, "aria-label" is required.',
      );
    }
  }
  const heading =
    section.title !== undefined && section.title !== null ? (
      <div className={mergeClassName("oksDropdownSectionHeading", section.classNames?.heading)}>
        {section.title}
      </div>
    ) : null;

  const hasDivider = section.showDivider === true;

  return (
    <div className={mergeClassName("oksDropdownSection", section.classNames?.base)}>
      {heading}
      <div
        role="group"
        aria-label={label}
        className={mergeClassName("oksDropdownSectionGroup", section.classNames?.group)}
      >
        {section.items.map(({ key, element }) =>
          cloneElement(element as any, {
            itemKey: key,
            ...(section.hideSelectedIcon !== undefined
              ? { __sectionHideSelectedIcon: section.hideSelectedIcon }
              : {}),
            ...(section.itemClasses ? { __sectionItemClasses: section.itemClasses } : {}),
          }),
        )}
      </div>
      {hasDivider ? (
        <div className={mergeClassName("oksDropdownSectionDivider", section.classNames?.divider)} />
      ) : null}
    </div>
  );
}

export const DropdownItem = forwardRef<HTMLElement, DropdownItemProps>((props, ref) => {
  const {
    children,
    title,
    description,
    shortcut,
    startContent,
    endContent,
    selectedIcon,
    showDivider = false,
    href,
    target,
    rel,
    download,
    ping,
    referrerPolicy,
    isDisabled = false,
    isSelected,
    isReadOnly = false,
    hideSelectedIcon,
    closeOnSelect,
    classNames,
    onPress,
    onPressStart,
    onPressEnd,
    onPressChange,
    onPressUp,
    onKeyDown,
    onKeyUp,
    onClick,
    itemKey,
  } = props;

  const menu = useDropdownMenuContext();

  const key = itemKey ?? null;
  const hasKey = key !== null && key !== undefined && String(key).trim().length > 0;
  const disabled = !hasKey || isDisabled === true || menu.disabledKeys.has(key as any);

  const menuSelected =
    menu.selectionMode === "none"
      ? false
      : menu.selectedKeys === "all"
        ? true
        : menu.selectedKeys.has(key as any);

  const resolvedSelected = typeof isSelected === "boolean" ? isSelected : menuSelected;
  const focused = menu.focusedKey === key;

  const role =
    menu.selectionMode === "multiple"
      ? "menuitemcheckbox"
      : menu.selectionMode === "single"
        ? "menuitemradio"
        : "menuitem";

  const ariaChecked =
    menu.selectionMode === "none" ? undefined : resolvedSelected ? "true" : "false";

  const sectionItemClasses = (props as any).__sectionItemClasses as
    | Partial<Record<DropdownItemSlot, string>>
    | undefined;
  const sectionHideSelectedIcon = (props as any).__sectionHideSelectedIcon as
    | boolean
    | undefined;

  const effectiveHideSelectedIcon =
    hideSelectedIcon ?? sectionHideSelectedIcon ?? menu.hideSelectedIcon;

  const label = title ?? children;
  const resolvedTextValue = getItemTextValue(key ?? "", props);

  const baseClassName = mergeClassName(
    mergeClassName(
      mergeClassName("oksDropdownItem", menu.itemClasses?.base),
      sectionItemClasses?.base,
    ),
    classNames?.base,
  );

  const [isPressedState, setIsPressedState] = useState(false);

  const startPress = (e: DropdownPressEvent) => {
    if (disabled) return;
    if (!isPressedState) {
      onPressStart?.(e);
      onPressChange?.(true);
    }
    setIsPressedState(true);
  };

  const endPress = (e: DropdownPressEvent) => {
    if (isPressedState) {
      onPressEnd?.(e);
      onPressChange?.(false);
    }
    setIsPressedState(false);
  };

  const activate = () => {
    if (disabled) return;
    if (!hasKey) return;
    menu.setFocusedKey(key);
    menu.onItemAction(key, props);
  };

  const Component: any = href ? "a" : "div";

  const itemEl = (
    <Component
      ref={mergeRefs(ref as any, (node: any) => {
        if (!hasKey) return;
        menu.registerItemRef(
          key as any,
          node instanceof HTMLElement ? node : null,
          { key: key as any, disabled, textValue: resolvedTextValue } satisfies ItemInfo,
        );
      })}
      role={role}
      aria-checked={ariaChecked}
      aria-disabled={disabled ? "true" : undefined}
      tabIndex={-1}
      data-disabled={disabled ? "true" : "false"}
      data-selected={resolvedSelected ? "true" : "false"}
      data-focused={focused ? "true" : "false"}
      className={baseClassName}
      href={href}
      target={target}
      rel={rel}
      download={download as any}
      ping={ping}
      referrerPolicy={referrerPolicy as any}
      onMouseMove={() => {
        if (!disabled) menu.setFocusedKey(key);
      }}
      onFocus={() => {
        if (!disabled) menu.setFocusedKey(key);
      }}
      onPointerDown={(e: ReactPointerEvent<HTMLElement>) => {
        startPress(e);
      }}
      onPointerUp={(e: ReactPointerEvent<HTMLElement>) => {
        if (disabled) return;
        onPressUp?.(e);
        endPress(e);
      }}
      onPointerLeave={(e: ReactPointerEvent<HTMLElement>) => {
        endPress(e);
      }}
      onPointerCancel={(e: ReactPointerEvent<HTMLElement>) => {
        endPress(e);
      }}
      onKeyDown={(e: KeyboardEvent<HTMLElement>) => {
        onKeyDown?.(e);
        if (e.defaultPrevented) return;
        if (e.key === "Enter" || e.key === " ") {
          startPress(e);
        }
      }}
      onKeyUp={(e: KeyboardEvent<HTMLElement>) => {
        onKeyUp?.(e);
        if (e.defaultPrevented) return;
        if (e.key === "Enter" || e.key === " ") {
          if (disabled) return;
          onPressUp?.(e);
          endPress(e);
        }
      }}
      onBlur={(e: ReactFocusEvent<HTMLElement>) => {
        endPress(e);
      }}
      onClick={(e: ReactMouseEvent<HTMLElement>) => {
        onClick?.(e);
        if (e.defaultPrevented) return;
        if (disabled) return;
        onPress?.(e);
        activate();
      }}
    >
      {startContent !== undefined && startContent !== null ? (
        <span className="oksDropdownItemStartContent" aria-hidden="true">
          {startContent}
        </span>
      ) : null}

      <span
        className={mergeClassName(
          mergeClassName(
            mergeClassName("oksDropdownItemWrapper", menu.itemClasses?.wrapper),
            sectionItemClasses?.wrapper,
          ),
          classNames?.wrapper,
        )}
      >
        <span
          className={mergeClassName(
            mergeClassName(
              mergeClassName("oksDropdownItemTitle", menu.itemClasses?.title),
              sectionItemClasses?.title,
            ),
            classNames?.title,
          )}
        >
          {label}
        </span>
        {description !== undefined && description !== null ? (
          <span
            className={mergeClassName(
              mergeClassName(
                mergeClassName("oksDropdownItemDescription", menu.itemClasses?.description),
                sectionItemClasses?.description,
              ),
              classNames?.description,
            )}
          >
            {description}
          </span>
        ) : null}
      </span>

      {shortcut !== undefined && shortcut !== null ? (
        <span
          className={mergeClassName(
            mergeClassName(
              mergeClassName("oksDropdownItemShortcut", menu.itemClasses?.shortcut),
              sectionItemClasses?.shortcut,
            ),
            classNames?.shortcut,
          )}
        >
          {shortcut}
        </span>
      ) : null}

      {endContent !== undefined && endContent !== null ? (
        <span className="oksDropdownItemEndContent" aria-hidden="true">
          {endContent}
        </span>
      ) : resolvedSelected && effectiveHideSelectedIcon !== true ? (
        <span
          className={mergeClassName(
            mergeClassName(
              mergeClassName("oksDropdownItemSelectedIcon", menu.itemClasses?.selectedIcon),
              sectionItemClasses?.selectedIcon,
            ),
            classNames?.selectedIcon,
          )}
          aria-hidden="true"
        >
          {selectedIcon ?? "✓"}
        </span>
      ) : null}
    </Component>
  );

  return showDivider ? (
    <>
      {itemEl}
      <div className="oksDropdownItemDivider" aria-hidden="true" />
    </>
  ) : (
    itemEl
  );
});

DropdownItem.displayName = "DropdownItem";

export const DropdownSection = (props: DropdownSectionProps) => {
  return null;
};

DropdownSection.displayName = "DropdownSection";
